// ─── QR FULLSCREEN — modal pantalla completa para mostrar un QR ──────────────
// Pensado para los dos casos del producto:
//   • merchant: el dueño abre su QR para que un cliente lo escanee y se sume
//     al club. Adicionalmente, debajo aparecen dos botones "Compartir" y
//     "Copiar URL" para distribución digital.
//   • client: el cliente abre su pase personal para que el comerciante lo
//     escanee en caja. Solo el QR + título, sin botones extra.
//
// Estética inspirada en pases tipo "Apple Wallet / Nike Experience":
//   - Fondo gradient violeta/naranja de marca, sin chrome de modal.
//   - Título gigante en tipografía display (Impact / Anton stack), random
//     dentro de un set por audiencia para que se sienta vivo.
//   - QR negro sobre fondo blanco, en una card grande centrada.
//   - X cerrar arriba a la derecha, glass discreto.
function QrFullscreen({ open, onClose, qrValue, audience = 'client', shareUrl = '', shareTitle = 'Benefix', displayName = '' }) {
  const [copied, setCopied] = useState(false)

  const topLabel = audience === 'merchant'
    ? `QR DE ${(shareTitle && shareTitle !== 'Benefix' ? shareTitle : 'MI NEGOCIO').toUpperCase()}`
    : 'QR PERSONAL'
  const ticketInstruction = audience === 'merchant'
    ? 'ESCANEÁ PARA UNIRTE AL CLUB'
    : 'ESCANEÁ ESTE QR EN EL NEGOCIO'
  const bottomName = displayName || (shareTitle && shareTitle !== 'Benefix' ? shareTitle : '')

  // kept for buildShareImage
  const title    = audience === 'merchant' ? 'QR NEGOCIO' : 'QR PERSONAL'
  const subtitle = ticketInstruction
  if (!open) return null
  async function handleCopy() {
    if (!shareUrl) return
    try {
      await navigator.clipboard.writeText(shareUrl)
      setCopied(true)
      setTimeout(() => setCopied(false), 1800)
    } catch {}
  }
  // Genera un PNG idéntico a la pantalla fullscreen:
  // logo Benefix arriba centrado, label pequeño, ticket blanco con QR,
  // instrucción, borde dentado y nombre debajo — todo sobre fondo violeta.
  async function buildShareImage() {
    if (typeof document === 'undefined') return null

    const W = 1080, H = 1920  // taller para respirar como en pantalla
    const canvas = document.createElement('canvas')
    canvas.width  = W
    canvas.height = H
    const ctx = canvas.getContext('2d')
    if (!ctx) return null

    const VIOLET = '#7131E1'
    const FONT   = "'Space Grotesk', system-ui, sans-serif"

    // ── 1. Fondo violeta ─────────────────────────────────────────────────
    ctx.fillStyle = VIOLET
    ctx.fillRect(0, 0, W, H)

    // ── 2. Logo Benefix — cargado desde el SVG público ───────────────────
    const LOGO_H  = 150   // alto del logo en canvas (≈ 60px × ratio de pantalla)
    const LOGO_Y  = 130   // distancia desde el tope
    try {
      const logoImg = new Image()
      logoImg.src = `${window.location.origin}/brand/logo-benefix-wordmark-white.svg`
      await new Promise(r => { logoImg.onload = r; logoImg.onerror = r })
      if (logoImg.naturalWidth > 0) {
        const logoW = logoImg.naturalWidth * (LOGO_H / logoImg.naturalHeight)
        ctx.drawImage(logoImg, (W - logoW) / 2, LOGO_Y, logoW, LOGO_H)
      }
    } catch {}

    // ── 3. Label ("QR PERSONAL" / "QR DE MI NEGOCIO") ────────────────────
    const LABEL_Y = LOGO_Y + LOGO_H + 80
    ctx.font         = `700 34px ${FONT}`
    ctx.fillStyle    = 'rgba(255,255,255,0.55)'
    ctx.textAlign    = 'center'
    ctx.textBaseline = 'top'
    ctx.fillText(topLabel, W / 2, LABEL_Y)

    // ── 4. Ticket blanco ──────────────────────────────────────────────────
    const TX     = 90           // margen horizontal
    const TY     = LABEL_Y + 80 // tope del ticket
    const TW     = W - TX * 2   // ancho = 900px
    const CORNER = 52

    const QR_SIZE = 660
    const QR_X   = (W - QR_SIZE) / 2
    const QR_Y   = TY + 70

    const INSTR_Y    = QR_Y + QR_SIZE + 52
    const INSTR_SIZE = 34

    const T_BODY_BOTTOM = INSTR_Y + INSTR_SIZE + 72

    // Rectángulo blanco con esquinas superiores redondeadas
    ctx.fillStyle = '#ffffff'
    ctx.beginPath()
    ctx.moveTo(TX + CORNER, TY)
    ctx.lineTo(TX + TW - CORNER, TY)
    ctx.arcTo(TX + TW, TY, TX + TW, TY + CORNER, CORNER)
    ctx.lineTo(TX + TW, T_BODY_BOTTOM)
    ctx.lineTo(TX, T_BODY_BOTTOM)
    ctx.lineTo(TX, TY + CORNER)
    ctx.arcTo(TX, TY, TX + CORNER, TY, CORNER)
    ctx.closePath()
    ctx.fill()

    // ── 5. QR dentro del ticket ───────────────────────────────────────────
    try {
      const QRCode  = (await import('qrcode')).default
      const qrDataU = await QRCode.toDataURL(qrValue || '', {
        width: QR_SIZE,
        margin: 1,
        errorCorrectionLevel: 'H',
        color: { dark: '#0a0a0a', light: '#ffffff' },
      })
      const qrImg = new Image()
      qrImg.src   = qrDataU
      await new Promise(r => { qrImg.onload = r; qrImg.onerror = r })
      ctx.drawImage(qrImg, QR_X, QR_Y, QR_SIZE, QR_SIZE)
    } catch {}

    // ── 6. Instrucción dentro del ticket ──────────────────────────────────
    ctx.font         = `800 ${INSTR_SIZE}px ${FONT}`
    ctx.fillStyle    = '#1a1a1a'
    ctx.textAlign    = 'center'
    ctx.textBaseline = 'top'
    ctx.fillText(ticketInstruction, W / 2, INSTR_Y)

    // ── 7. Borde dentado (semicírculos violetas) ──────────────────────────
    const SERR_R   = 30
    const SERR_GAP = 60
    ctx.fillStyle  = VIOLET
    let sx = TX + SERR_GAP / 2
    while (sx < TX + TW) {
      ctx.beginPath()
      ctx.arc(sx, T_BODY_BOTTOM, SERR_R, 0, Math.PI * 2)
      ctx.fill()
      sx += SERR_GAP
    }

    // ── 8. Nombre debajo del ticket ───────────────────────────────────────
    if (bottomName) {
      ctx.font         = `700 62px ${FONT}`
      ctx.fillStyle    = 'rgba(255,255,255,0.92)'
      ctx.textAlign    = 'center'
      ctx.textBaseline = 'top'
      ctx.fillText(bottomName, W / 2, T_BODY_BOTTOM + SERR_R * 2 + 52)
    }

    // ── 9. Watermark ──────────────────────────────────────────────────────
    ctx.font         = `500 28px ${FONT}`
    ctx.fillStyle    = 'rgba(255,255,255,0.30)'
    ctx.textAlign    = 'center'
    ctx.textBaseline = 'bottom'
    ctx.fillText('benefix.com.ar', W / 2, H - 70)

    return new Promise(resolve => canvas.toBlob(b => resolve(b), 'image/png', 1))
  }

  async function handleShare() {
    let blob = null
    try { blob = await buildShareImage() } catch {}
    const fileName = `${(shareTitle || 'benefix').toLowerCase().replace(/[^a-z0-9]+/g, '-')}-qr.png`
    const file = blob ? new File([blob], fileName, { type: 'image/png' }) : null

    // Intento 1: share API con archivo (mobile moderno)
    if (file && typeof navigator !== 'undefined' && navigator.canShare && navigator.canShare({ files: [file] })) {
      try {
        await navigator.share({
          files: [file],
          title: shareTitle,
          text: audience === 'merchant'
            ? `${shareTitle} en Benefix — escaneá para sumarte al club`
            : 'Mi QR de Benefix',
          ...(shareUrl ? { url: shareUrl } : {}),
        })
        return
      } catch { /* user canceled */ }
    }

    // Intento 2: share API solo con URL (desktop / browsers viejos)
    if (shareUrl && typeof navigator !== 'undefined' && navigator.share) {
      try {
        await navigator.share({
          title: shareTitle,
          text: `${shareTitle} en Benefix — sumate al club`,
          url: shareUrl,
        })
        return
      } catch { /* user canceled */ }
    }

    // Intento 3: descarga el PNG
    if (blob) {
      try {
        const url = URL.createObjectURL(blob)
        const a = document.createElement('a')
        a.href = url
        a.download = fileName
        document.body.appendChild(a)
        a.click()
        a.remove()
        setTimeout(() => URL.revokeObjectURL(url), 1000)
        return
      } catch {}
    }

    // Último fallback: copiar URL
    if (shareUrl) handleCopy()
  }

  return (
    <div role="dialog" aria-modal="true" style={{
      position: 'fixed', inset: 0, zIndex: 99999,
      background: '#7131E1',
      display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      padding: `64px 24px calc(32px + env(safe-area-inset-bottom, 0px))`,
      overflow: 'hidden',
    }}>
      {/* X — sin fondo, esquina superior derecha */}
      <button onClick={onClose} aria-label="Cerrar" style={{
        position: 'absolute', top: 20, right: 20, zIndex: 5,
        background: 'none', border: 'none',
        color: 'rgba(255,255,255,0.85)', cursor: 'pointer',
        padding: 8, lineHeight: 0,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
      }}>
        <X size={24} strokeWidth={2} />
      </button>

      {/* Logo centrado arriba */}
      <div style={{
        position: 'absolute', top: 22, left: 0, right: 0,
        display: 'flex', justifyContent: 'center', pointerEvents: 'none',
      }}>
        <Logo size="sm" style={{ height: 60 }} />
      </div>

      {/* Label superior */}
      <div style={{
        fontFamily: FN, fontSize: 11, fontWeight: 700,
        letterSpacing: '.14em', textTransform: 'uppercase',
        color: 'rgba(255,255,255,0.55)', marginBottom: 24,
        textAlign: 'center',
      }}>
        {topLabel}
      </div>

      {/* Ticket */}
      <div style={{ width: '100%', maxWidth: 300, boxShadow: '0 8px 40px rgba(0,0,0,0.30)' }}>
        {/* Cuerpo blanco del ticket */}
        <div style={{
          background: '#fff',
          borderRadius: '16px 16px 0 0',
          padding: '28px 24px 20px',
          display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 16,
        }}>
          <QRCodeSVG
            value={qrValue || ''}
            size={210}
            fgColor="#0a0a0a"
            bgColor="#ffffff"
            level="H"
            style={{ display: 'block' }}
          />
          <div style={{
            fontFamily: FN, fontSize: 10, fontWeight: 800,
            color: '#1a1a1a', letterSpacing: '.12em',
            textTransform: 'uppercase', textAlign: 'center',
            lineHeight: 1.4,
          }}>
            {ticketInstruction}
          </div>
        </div>
        {/* Borde dentado inferior — semicírculos violeta que muerden el blanco */}
        <div style={{
          width: '100%', height: 10,
          backgroundImage: 'radial-gradient(circle at 50% 100%, #7131E1 6px, #fff 7px)',
          backgroundSize: '16px 10px',
          backgroundRepeat: 'repeat-x',
        }} />
      </div>

      {/* Nombre debajo del ticket */}
      {bottomName && (
        <div style={{
          marginTop: 28,
          fontFamily: FN, fontSize: 16, fontWeight: 700,
          color: 'rgba(255,255,255,0.90)', textAlign: 'center',
          letterSpacing: '-.01em',
        }}>
          {bottomName}
        </div>
      )}

      {/* Botones compartir */}
      <div style={{ display: 'flex', gap: 10, marginTop: 24 }}>
        <button onClick={handleShare} style={{
          display: 'flex', alignItems: 'center', gap: 7,
          padding: '10px 18px',
          background: 'rgba(255,255,255,0.14)',
          border: '1px solid rgba(255,255,255,0.22)',
          borderRadius: 99, color: '#fff',
          fontFamily: FN, fontSize: 13, fontWeight: 600, cursor: 'pointer',
          lineHeight: 1,
        }}>
          <Share2 size={14} strokeWidth={2.2} />
          Compartir
        </button>
        {audience === 'merchant' && shareUrl && (
          <button onClick={handleCopy} style={{
            display: 'flex', alignItems: 'center', gap: 7,
            padding: '10px 18px',
            background: 'rgba(255,255,255,0.14)',
            border: '1px solid rgba(255,255,255,0.22)',
            borderRadius: 99, color: '#fff',
            fontFamily: FN, fontSize: 13, fontWeight: 600, cursor: 'pointer',
            lineHeight: 1,
          }}>
            {copied ? <Check size={14} strokeWidth={2.4} /> : <Copy size={14} strokeWidth={2.2} />}
            {copied ? '¡Copiado!' : 'Copiar URL'}
          </button>
        )}
      </div>
    </div>
  )
}

// ─── QR DEL NEGOCIO ───────────────────────────────────────────────────────────
function CommerceQRCard({ commerce }) {
  const [qrDataUrl,      setQrDataUrl]      = useState(null)
  const [printQrDataUrl, setPrintQrDataUrl] = useState(null)
  const [copied,         setCopied]         = useState(false)
  const [slug,           setSlug]           = useState(commerce?.slug || '')
  const [savingSlug,     setSavingSlug]     = useState(false)
  const [showDownload,   setShowDownload]   = useState(false)
  const [downloading,    setDownloading]    = useState(false)
  const storyRef = useRef(null)
  const printRef = useRef(null)
  const supabase = getSupabase()

  // ?from_qr=1 activa el "spotlight" sobre el slider en /club/[slug] cuando
  // el cliente entra escaneando este QR (oscurece el resto de la pantalla
  // y enfoca al botón "Deslizá para unirte").
  const joinUrl = typeof window !== 'undefined' && slug
    ? `${window.location.origin}/club/${slug}?from_qr=1`
    : ''

  useEffect(() => {
    if (commerce?.id && !commerce?.slug) {
      const generated = makeSlug(commerce.name) + '-' + commerce.id.slice(0, 4)
      setSavingSlug(true)
      supabase.from('commerces').update({ slug: generated }).eq('id', commerce.id)
        .then(() => { setSlug(generated); setSavingSlug(false) })
    }
  }, [commerce?.id])

  useEffect(() => {
    if (!joinUrl) return
    // QR negro sobre blanco puro: máxima detectabilidad para cualquier scanner.
    // Antes era blanco sobre transparente (estético pero peor para detectar).
    makeQR(joinUrl, { width: 300, margin: 2, dark: '#000000', light: '#FFFFFF' }).then(setQrDataUrl)
    makeQR(joinUrl, { width: 400, margin: 3, dark: '#000000', light: '#FFFFFF' }).then(setPrintQrDataUrl)
  }, [joinUrl])

  function copyLink() {
    navigator.clipboard.writeText(joinUrl).then(() => {
      setCopied(true)
      setTimeout(() => setCopied(false), 2000)
    })
  }

  async function downloadDigital() {
    if (!storyRef.current) return
    setDownloading('digital')
    try {
      const html2canvas = (await import('html2canvas')).default
      const canvas = await html2canvas(storyRef.current, {
        scale: 2, useCORS: true, backgroundColor: null, logging: false,
        width: 1080, height: 1920,
      })
      const a = document.createElement('a')
      a.download = `${slug}-historia.png`
      a.href = canvas.toDataURL('image/png')
      a.click()
    } finally {
      setDownloading(false)
    }
  }

  async function downloadPrint() {
    if (!printRef.current) return
    setDownloading('print')
    try {
      const html2canvas = (await import('html2canvas')).default
      const canvas = await html2canvas(printRef.current, {
        scale: 3, useCORS: true, backgroundColor: '#FFFFFF', logging: false,
      })
      const a = document.createElement('a')
      a.download = `qr-${slug}-imprimir.png`
      a.href = canvas.toDataURL('image/png')
      a.click()
    } finally {
      setDownloading(false)
    }
  }

  if (savingSlug || !slug) return null

  return (
    <>
      <PCard style={{ padding:'20px', marginBottom:14, border:`1px solid ${C.v}33` }}>
        <div style={{ display:'flex', alignItems:'center', gap:6, marginBottom:4 }}>
          <QrCode size={13} color='rgba(255,255,255,0.70)' strokeWidth={2} />
          <div style={{ fontFamily:FN, fontSize:13, fontWeight:700, color:C.white }}>QR de tu negocio</div>
          <InfoTooltip text="Este QR lleva a la página de registro de tu club. Pegalo en la caja o mostralo en tu negocio para que los clientes se unan escaneándolo." />
        </div>
        <div style={{ fontSize:11, color:C.mist, marginBottom:16 }}>Compartilo para que tus clientes se unan al club.</div>

        {/* Gradient QR card */}
        <div style={{
          background:'#7131E1',
          borderRadius:20, padding:'20px 20px 16px', marginBottom:14,
          position:'relative', overflow:'hidden',
        }}>
          <div className="qr-shimmer" style={{
            position:'absolute', inset:0, pointerEvents:'none',
            background:'linear-gradient(105deg, transparent 40%, rgba(255,255,255,0.18) 50%, transparent 60%)',
          }} />
          <div style={{ position:'relative', display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:14 }}>
            <div>
              <div style={{ fontSize:9, color:'rgba(255,255,255,0.60)', textTransform:'uppercase', letterSpacing:'0.10em', marginBottom:2 }}>Benefix</div>
              <div style={{ fontFamily:FN, fontSize:17, fontWeight:700, color:'#fff' }}>{commerce?.name}</div>
            </div>
            <div style={{ width:36, height:36, borderRadius:'50%', background:'rgba(255,255,255,0.15)', display:'flex', alignItems:'center', justifyContent:'center' }}>
              <Store size={18} color="white" strokeWidth={1.5} />
            </div>
          </div>
          <div style={{ position:'relative', display:'flex', justifyContent:'center', marginBottom:14 }}>
            <div style={{ background:'rgba(255,255,255,0.12)', borderRadius:16, padding:12, position:'relative', display:'inline-block' }}>
              {qrDataUrl
                ? <img src={qrDataUrl} alt="QR" style={{ width:160, height:160, display:'block' }} />
                : <div style={{ width:160, height:160, display:'flex', alignItems:'center', justifyContent:'center', color:'rgba(255,255,255,0.50)', fontSize:11 }}>Generando...</div>
              }
            </div>
          </div>
          <div style={{ position:'relative', textAlign:'center', fontSize:11, color:'rgba(255,255,255,0.55)' }}>Escaneá para unirte al club</div>
        </div>

        {/* URL pill */}
        <div style={{ background:C.bg3, borderRadius:10, padding:'8px 12px', marginBottom:12 }}>
          <span style={{ fontSize:11, color:C.mist, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap', display:'block', fontFamily:FI }}>{joinUrl}</span>
        </div>

        {/* Actions */}
        <div style={{ display:'flex', gap:8 }}>
          <button onClick={copyLink} style={{
            flex:1, padding:'10px 12px',
            background: copied ? `${C.ok}22` : C.bg3,
            border:`1px solid ${copied ? C.ok : C.rim}`,
            borderRadius:10, color: copied ? C.ok : C.mist,
            fontFamily:FN, fontSize:11, fontWeight:700, cursor:'pointer',
            display:'flex', alignItems:'center', justifyContent:'center', gap:6,
          }}>
            {copied ? <><CheckCircle size={12} strokeWidth={2.5} />Copiado!</> : <><Copy size={12} strokeWidth={2} />Copiar link</>}
          </button>
          <button onClick={() => setShowDownload(true)} disabled={!qrDataUrl} style={{
            flex:1, padding:'10px 12px',
            background: C.v,
            border:'none', borderRadius:10, color:'#fff',
            fontFamily:FN, fontSize:11, fontWeight:700,
            cursor:qrDataUrl ? 'pointer' : 'not-allowed', opacity:qrDataUrl ? 1 : 0.5,
            display:'flex', alignItems:'center', justifyContent:'center', gap:6,
          }}>
            <Download size={12} strokeWidth={2} />Descargar
          </button>
        </div>
      </PCard>

      {/* Download options modal */}
      {showDownload && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.80)', backdropFilter:'blur(8px)', WebkitBackdropFilter:'blur(8px)', zIndex:300, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}
          onClick={() => !downloading && setShowDownload(false)}>
          <div className="modal-in" onClick={e => e.stopPropagation()} style={{
            background:'rgba(255,255,255,0.07)', backdropFilter:'blur(40px)', WebkitBackdropFilter:'blur(40px)',
            border:`1px solid ${C.rim}`, borderRadius:24, padding:24, maxWidth:340, width:'100%',
            boxShadow:'0 24px 80px rgba(0,0,0,0.5)',
          }}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:20 }}>
              <div style={{ fontFamily:FN, fontSize:16, fontWeight:700, color:C.white }}>Descargar QR</div>
              <button onClick={() => setShowDownload(false)} style={{ background:'none', border:'none', cursor:'pointer', color:C.mist, padding:4, lineHeight:0 }}>
                <X size={18} />
              </button>
            </div>
            <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
              <button onClick={downloadDigital} disabled={!!downloading} style={{
                width:'100%', padding:16, background:C.bg3, border:`1px solid ${C.rim}`,
                borderRadius:16, cursor:downloading ? 'not-allowed' : 'pointer',
                display:'flex', alignItems:'center', gap:14, textAlign:'left',
                opacity: downloading === 'digital' ? 0.6 : 1,
              }}>
                <div style={{ width:48, height:48, borderRadius:12, background:'#7131E1', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                  <Smartphone size={22} color="white" strokeWidth={1.5} />
                </div>
                <div>
                  <div style={{ fontFamily:FN, fontSize:13, fontWeight:600, color:C.white, marginBottom:3 }}>
                    {downloading === 'digital' ? 'Generando...' : 'Para pantallas'}
                  </div>
                  <div style={{ fontSize:11, color:C.mist }}>WhatsApp, Instagram, redes sociales</div>
                </div>
              </button>
              <button onClick={downloadPrint} disabled={!!downloading} style={{
                width:'100%', padding:16, background:C.bg3, border:`1px solid ${C.rim}`,
                borderRadius:16, cursor:downloading ? 'not-allowed' : 'pointer',
                display:'flex', alignItems:'center', gap:14, textAlign:'left',
                opacity: downloading === 'print' ? 0.6 : 1,
              }}>
                <div style={{ width:48, height:48, borderRadius:12, background:'#fff', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                  <Printer size={22} color="#1a1a2e" strokeWidth={1.5} />
                </div>
                <div>
                  <div style={{ fontFamily:FN, fontSize:13, fontWeight:600, color:C.white, marginBottom:3 }}>
                    {downloading === 'print' ? 'Generando...' : 'Para imprimir'}
                  </div>
                  <div style={{ fontSize:11, color:C.mist }}>QR negro, fondo blanco, ahorra tinta</div>
                </div>
              </button>
            </div>
            <div style={{ textAlign:'center', fontSize:10, color:C.dust, marginTop:14 }}>
              Ambas versiones incluyen el logo y datos de tu negocio
            </div>
          </div>
        </div>
      )}

      {/* Hidden Instagram story template (captured by html2canvas) */}
      <div ref={storyRef} style={{ position:'fixed', top:'-9999px', left:'-9999px', width:1080, height:1920 }}>
        <InstagramStoryQR commerce={commerce} qrDataUrl={printQrDataUrl} />
      </div>

      {/* Hidden printable template (captured by html2canvas) */}
      <div ref={printRef} style={{
        position:'fixed', top:'-9999px', left:'-9999px',
        width:400, padding:40, background:'#ffffff', textAlign:'center',
        fontFamily:'system-ui, -apple-system, sans-serif',
      }}>
        <div style={{ marginBottom:8 }}>
          <span style={{ fontSize:13, fontWeight:700, color:'#9333ea', textTransform:'uppercase', letterSpacing:'0.08em' }}>Benefix</span>
        </div>
        <div style={{ fontSize:26, fontWeight:700, color:'#111', marginBottom:24, lineHeight:1.2 }}>{commerce?.name}</div>
        <div style={{ display:'inline-block', padding:20, border:'2px solid #e5e7eb', borderRadius:16, marginBottom:20, position:'relative' }}>
          {printQrDataUrl && (
            <img src={printQrDataUrl} alt="QR" style={{ width:200, height:200, display:'block' }} />
          )}
        </div>
        <div style={{ fontSize:15, color:'#555', marginBottom:6 }}>Escaneá el código QR para unirte</div>
        <div style={{ fontSize:13, color:'#888', marginBottom:16 }}>y empezar a acumular beneficios</div>
        <div style={{ fontSize:11, color:'#bbb' }}>{joinUrl}</div>
      </div>
    </>
  )
}

// ─── UPGRADE RESULT MODAL ─────────────────────────────────────────────────────
// Se muestra cuando el dueño vuelve del checkout de Mercado Pago vía la URL
// con ?upgrade=success|pending|failure. El webhook MP es quien activa el plan
// realmente (POST /api/webhooks/mercadopago) — este modal es solo el feedback
// visual al usuario para que sepa que el flujo terminó (o no).
function UpgradeResultModal({ result, onClose }) {
  const isSuccess = result === 'success' || result === 'pending'
  const title = isSuccess
    ? '¡Pago en proceso!'
    : 'No se completó el pago'
  const body  = isSuccess
    ? 'Recibimos tu suscripción. En unos minutos vamos a activar tu nuevo plan automáticamente. Si pasaron más de 10 minutos y no se activó, escribinos por soporte.'
    : 'El pago no se completó o fue cancelado. Tu plan actual no cambió. Podés volver a intentarlo desde la pantalla de planes cuando quieras.'
  const accentColor = isSuccess ? '#22E698' : '#F87171'
  const accentBg    = isSuccess ? 'rgba(34,230,152,0.12)' : 'rgba(248,113,113,0.12)'
  const accentBorder= isSuccess ? 'rgba(34,230,152,0.45)' : 'rgba(248,113,113,0.45)'
  return (
    <div
      onClick={onClose}
      style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.78)', zIndex:300, display:'flex', alignItems:'center', justifyContent:'center', padding:20, backdropFilter:'blur(6px)', WebkitBackdropFilter:'blur(6px)' }}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          background:'linear-gradient(180deg, #15091F 0%, #0a0612 100%)',
          border:`1px solid ${accentBorder}`,
          borderRadius:24,
          padding:'32px 24px 24px',
          maxWidth:400, width:'100%',
          boxShadow:`0 24px 64px rgba(0,0,0,0.6), 0 0 0 2px ${accentBorder}`,
          textAlign:'center',
          fontFamily:'inherit',
        }}
      >
        <div style={{
          width:72, height:72, borderRadius:24,
          background:`linear-gradient(135deg, ${accentColor}, ${accentColor}AA)`,
          display:'flex', alignItems:'center', justifyContent:'center',
          margin:'0 auto 18px',
          boxShadow:`0 12px 36px ${accentColor}60`,
        }}>
          {isSuccess
            ? <Check size={36} color="#fff" strokeWidth={3} />
            : <X size={36} color="#fff" strokeWidth={3} />}
        </div>
        <div style={{ fontSize:22, fontWeight:900, color:'#fff', marginBottom:10, letterSpacing:'-.01em' }}>
          {title}
        </div>
        <div style={{ fontSize:14, color:'rgba(255,255,255,0.74)', lineHeight:1.55, marginBottom:24 }}>
          {body}
        </div>
        {isSuccess && (
          <div style={{
            padding:'10px 14px', borderRadius:12,
            background: accentBg,
            border:`1px solid ${accentBorder}`,
            fontSize:12, color:`${accentColor}`,
            fontWeight:700, marginBottom:16, textAlign:'left',
            display:'flex', alignItems:'flex-start', gap:8,
          }}>
            <Sparkles size={14} strokeWidth={2.4} style={{ flexShrink:0, marginTop:1 }} />
            <span style={{ color:'rgba(255,255,255,0.85)', fontWeight:500, lineHeight:1.45 }}>
              Vas a recibir un email de Mercado Pago con el comprobante. La activación es automática — no hace falta hacer nada más.
            </span>
          </div>
        )}
        <button
          onClick={onClose}
          style={{
            width:'100%', padding:'14px 18px', borderRadius:14,
            background: isSuccess
              ? '#7131E1'
              : 'rgba(255,255,255,0.08)',
            border: isSuccess ? 'none' : '1px solid rgba(255,255,255,0.16)',
            color:'#fff',
            fontSize:14, fontWeight:800, letterSpacing:'.02em',
            cursor:'pointer',
            boxShadow: isSuccess ? '0 8px 24px rgba(189,75,248,0.45)' : 'none',
          }}
        >
          {isSuccess ? 'Volver al panel' : 'Entendido'}
        </button>
      </div>
    </div>
  )
}

// ─── UPGRADE MODAL ────────────────────────────────────────────────────────────
function UpgradeModal({ feature, onUpgrade, onViewPlans, onContactSupport, onClose }) {
  const gate = FEATURE_GATES[feature]
  if (!gate) return null
  const planDef = PLANS[gate.ctaPlan]
  return (
    <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,.75)', zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}
      onClick={onClose}>
      <div onClick={e => e.stopPropagation()} className="modal-in"
        style={{ background:'rgba(255,255,255,0.08)', backdropFilter:'blur(40px)', WebkitBackdropFilter:'blur(40px)', border:`1px solid ${C.v}44`, borderRadius:20, padding:28, maxWidth:380, width:'100%', position:'relative',
          boxShadow:`0 0 0 1px ${C.v}22, 0 24px 64px rgba(0,0,0,.6), 0 0 80px rgba(189,75,248,.15)` }}>
        {/* Glow top */}
        <div style={{ position:'absolute', top:0, left:'50%', transform:'translateX(-50%)', width:180, height:2, background:GV, borderRadius:2 }} />

        <button onClick={onClose}
          style={{ position:'absolute', top:14, right:16, background:'transparent', border:'none', color:C.mist, fontSize:18, cursor:'pointer', lineHeight:1 }}>✕</button>

        {/* Icon */}
        <div style={{ width:52, height:52, borderRadius:14, background:`${C.v}22`, border:`1px solid ${C.v}44`, display:'flex', alignItems:'center', justifyContent:'center', marginBottom:16 }}>
          {(() => { const I = gate.Icon; return I ? <I size={24} color='rgba(255,255,255,0.80)' strokeWidth={2} /> : null })()}
        </div>

        <div style={{ fontFamily:FN, fontSize:18, fontWeight:900, color:C.white, marginBottom:8, lineHeight:1.2 }}>{gate.title}</div>
        <div style={{ fontSize:13, color:C.mist, lineHeight:1.6, marginBottom:16 }}>{gate.description}</div>

        <ul style={{ margin:'0 0 20px', padding:0, listStyle:'none', display:'flex', flexDirection:'column', gap:6 }}>
          {gate.bullets.map(b => (
            <li key={b} style={{ fontSize:12, color:C.pearl, display:'flex', alignItems:'flex-start', gap:8 }}>
              <span style={{ color:planDef.color, fontWeight:700, flexShrink:0 }}>✓</span> {b}
            </li>
          ))}
        </ul>

        <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:8 }}>
          <span style={{ fontFamily:FN, fontSize:10, fontWeight:700, color:planDef.color, background:planDef.badge, padding:'2px 8px', borderRadius:6, letterSpacing:'.07em' }}>{planDef.label}</span>
          <span style={{ fontFamily:FN, fontSize:14, fontWeight:900, color:C.white }}>${planDef.price.toLocaleString('es-AR')} / mes</span>
          <span style={{ fontSize:10, color:C.dust }}>· menos de $850/día</span>
        </div>

        <button onClick={() => onUpgrade(gate.ctaPlan)}
          style={{ width:'100%', padding:'13px', background:GV, border:'none', borderRadius:12, color:'#fff', fontFamily:FN, fontSize:13, fontWeight:700, cursor:'pointer', marginBottom:10, boxShadow:`0 4px 16px rgba(189,75,248,.4)`, display:'flex', alignItems:'center', justifyContent:'center', gap:6 }}>
          <Zap size={14} strokeWidth={2} /> {gate.ctaLabel}
        </button>
        <button onClick={onViewPlans}
          style={{ width:'100%', padding:'10px', background:'transparent', border:`1px solid ${C.rim}`, borderRadius:12, color:C.mist, fontFamily:FN, fontSize:12, fontWeight:600, cursor:'pointer' }}>
          Ver todos los planes
        </button>
        {onContactSupport && (
          <div style={{ marginTop:14, paddingTop:12, borderTop:`1px solid ${C.rim}`, textAlign:'center' }}>
            <button onClick={() => onContactSupport(gate.ctaPlan)}
              style={{ background:'transparent', border:'none', color:C.dust, fontFamily:FI, fontSize:11, fontWeight:500, cursor:'pointer', padding:0, textDecoration:'underline', textUnderlineOffset:3 }}>
              ¿Problemas con el pago? Escribinos por WhatsApp
            </button>
          </div>
        )}
      </div>
    </div>
  )
}

// ─── BTN — shared button variants ────────────────────────────────────────────
// variant: 'primary' | 'secondary' | 'ghost' | 'outline'
// size:    'sm' | 'md' | 'lg'
function Btn({ variant = 'primary', size = 'md', onClick, children, style: xs, ...rest }) {
  const [hov, setHov] = useState(false)
  const pad  = { sm:'10px 20px', md:'14px 28px', lg:'16px 36px' }
  const fs   = { sm:12, md:14, lg:16 }
  const base = {
    display:'inline-flex', alignItems:'center', justifyContent:'center', gap:8,
    padding:pad[size], borderRadius:9999,
    fontFamily:FN, fontSize:fs[size], fontWeight:700,
    cursor:'pointer', border:'none', outline:'none',
    transition:'transform 160ms cubic-bezier(0.23,1,0.32,1), box-shadow 160ms ease, color 160ms ease',
  }
  const V = {
    primary: {
      background: G, color:'#fff',
      boxShadow: hov ? '0 8px 32px rgba(254,80,0,0.35)' : '0 4px 16px rgba(254,80,0,0.18)',
      transform: hov ? 'scale(1.04)' : 'scale(1)',
    },
    secondary: {
      background:'rgba(255,255,255,0.08)', color:C.white,
      border:'1px solid rgba(255,255,255,0.14)',
      backdropFilter:'blur(12px)', WebkitBackdropFilter:'blur(12px)',
      transform: hov ? 'scale(1.02)' : 'scale(1)',
    },
    ghost: {
      background:'transparent', border:'none',
      color: hov ? C.white : 'rgba(255,255,255,0.55)',
      transform:'scale(1)',
    },
    outline: {
      background:'transparent',
      border:`1px solid ${hov ? 'rgba(168,85,247,0.65)' : 'rgba(168,85,247,0.40)'}`,
      color: hov ? '#d8b4fe' : '#c084fc',
      transform: hov ? 'scale(1.02)' : 'scale(1)',
    },
  }
  return (
    <button
      onClick={onClick}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{ ...base, ...(V[variant] || V.primary), ...xs }}
      {...rest}
    >
      {children}
    </button>
  )
}

// ─── PLAN CARDS ──────────────────────────────────────────────────────────────
// currentPlan: 'free'|'starter'|'pro'|null  (null = vista pública sin sesión)
// clientCount/planLimit: para barra de uso (solo en panel)
// onUpgrade(key): callback al hacer upgrade
// onCTA: callback para botón en home (registro)
function PlanCards({ currentPlan=null, clientCount=0, planLimit=null, onUpgrade, onCTA }) {
  const PLAN_LIST = [
    // Features actualizados may 2026 contra PLAN_PERMISSIONS reales:
    //   - FREE:    max_clients=30, max_rewards=2, no promos, no automatizaciones
    //   - STARTER: max_clients=60, premios ilimitados, promos sí, no autom.
    //   - PRO:     todo ilimitado + mensajes automáticos por WhatsApp
    {
      key:'free',
      Icon: Package,
      tagline:'Para clubes que recién arrancan.',
      sub:'Perfecto para empezar sin compromiso',
      features:[
        'Hasta 30 clientes activos',
        'Sistema de puntos o estrellas',
        'Hasta 2 premios cargados',
        'Escáner QR desde tu celular',
        'Historial de visitas y canjes',
      ],
      price:0,
      priceHint:null,
      cta:null,
    },
    {
      key:'starter',
      Icon: Zap,
      tagline:'Cuando ya tenés clientes que vuelven.',
      sub:'Convertí visitas en clientes recurrentes',
      badge:'★ Más elegido',
      features:[
        'Hasta 60 clientes activos',
        'Premios ilimitados',
        'Cupón de descuento en próxima compra',
        'Días con suma ×2',
        'Soporte prioritario por chat',
        'Todo lo del FREE incluido',
      ],
      price:25000,
      priceHint:'Menos de $850 por día',
      cta:'Empezá con STARTER →',
    },
    {
      key:'pro',
      Icon: Rocket,
      tagline:'Para locales con mucho movimiento.',
      sub:'Para negocios con alto volumen de clientes',
      features:[
        'Clientes ilimitados',
        'Mensajes automáticos por WhatsApp',
        'Reactivar clientes inactivos',
        'Aviso cuando un cliente está cerca de canjear',
        'Saludo automático en primera visita',
        'Todo lo del STARTER incluido',
      ],
      price:45000,
      priceHint:null,
      cta:'Activá PRO →',
    },
  ]

  function fmtPrice(p) {
    if (p === 0) return 'Gratis'
    return `$${p.toLocaleString('es-AR')} / mes`
  }

  const [isMobile, setIsMobile] = useState(false)

  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth < 768)
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  function renderCard({ key, Icon, tagline, sub, badge, features, price, priceHint, cta }) {
    const def          = PLANS[key]
    const isCurrent    = currentPlan === key
    const isStarter    = key === 'starter'
    const planOrder    = ['free','starter','pro']
    const isUpgrade    = currentPlan && planOrder.indexOf(currentPlan) < planOrder.indexOf(key)
    const showUsageBar = isCurrent && planLimit !== null

    // Acento general (tildes) → SIEMPRE violeta de marca en las 3 cards.
    // El destacado del plan recomendado (STARTER) sigue dado por el glow,
    // borde y CTA fill — los tildes en violeta refuerzan identidad de marca
    // sin romper la jerarquía visual.
    const accent = C.v

    // Plan label en MAYÚSCULAS (FREE / STARTER / PRO) — usamos def.label
    // porque está en castellano de marca y Chrome no lo traduce. Una versión
    // anterior usó Title Case en inglés ("Free", "Starter", "Pro") y Chrome
    // detectó la página como inglés y tradujo TODO al castellano automático
    // ("Starter" → "Motor de arranque", "/ mes" → "/ nosotros"...).

    return (
      <div key={key} style={{
        position: 'relative',
        background: 'rgba(255,255,255,0.025)',
        border: isStarter
          ? `1px solid ${C.v}80`
          : isCurrent
            ? `1px solid ${def.color}55`
            : '1px solid rgba(255,255,255,0.08)',
        borderRadius: 18,
        padding: '22px 20px 20px',
        backdropFilter: 'blur(14px)', WebkitBackdropFilter: 'blur(14px)',
        // Glow exterior + halo interno solo en STARTER (equivalente al
        // resplandor teal de la referencia, en violeta de marca).
        boxShadow: isStarter
          ? `0 0 0 1px ${C.v}40, 0 0 70px -10px ${C.v}80, inset 0 0 80px -30px ${C.v}55`
          : 'none',
        overflow: 'visible',
        display: 'flex', flexDirection: 'column', height: '100%',
        boxSizing: 'border-box',
        transition: 'box-shadow .25s, border-color .25s, transform .25s',
      }}>

        {/* Badge "MÁS ELEGIDO" — pill arriba-derecha estilo ref. Para el
            plan ACTUAL del comerciante (no en home) sumamos un chip al lado. */}
        {badge && (
          <div translate="no" style={{
            position: 'absolute', top: 12, right: 12,
            background: `${C.v}1f`,
            border: `1px solid ${C.v}66`,
            color: '#E9D5FF',
            borderRadius: 99,
            padding: '4px 9px',
            fontSize: 8.5, fontWeight: 700, fontFamily: FN,
            letterSpacing: '.10em',
            textTransform: 'uppercase',
            whiteSpace: 'nowrap',
            boxShadow: `0 4px 16px ${C.v}40`,
          }}>
            ★ Más elegido
          </div>
        )}
        {isCurrent && !badge && (
          <div translate="no" style={{
            position: 'absolute', top: 12, right: 12,
            background: 'rgba(255,255,255,0.06)',
            border: '1px solid rgba(255,255,255,0.14)',
            color: C.pearl,
            fontFamily: FN, fontSize: 8.5, fontWeight: 700,
            padding: '4px 9px', borderRadius: 99,
            letterSpacing: '.10em', textTransform: 'uppercase',
          }}>
            Plan actual
          </div>
        )}

        {/* Plan name (mayúsculas + translate=no para evitar auto-traducción) */}
        <div translate="no" style={{
          fontFamily: FN, fontSize: 13, fontWeight: 800,
          color: C.white, marginBottom: 2, letterSpacing: '.02em',
        }}>
          {def.label}
        </div>
        <div style={{
          fontFamily: FI, fontSize: 11, color: 'rgba(255,255,255,0.45)',
          marginBottom: 18,
        }}>
          Facturación mensual
        </div>

        {/* Precio: número grande + "/ mes" en gris (con translate=no por las
            dudas, "/ mes" se estaba traduciendo a "/ nosotros" en Chrome). */}
        <div style={{ display: 'flex', alignItems: 'baseline', gap: 5, marginBottom: 4, flexWrap: 'wrap' }}>
          <span translate="no" style={{
            fontFamily: FN, fontSize: 'clamp(28px, 4.2vw, 36px)',
            fontWeight: 700, color: C.white, lineHeight: 1,
            letterSpacing: '-.03em',
          }}>
            {price === 0 ? 'Gratis' : `$${price.toLocaleString('es-AR')}`}
          </span>
          {price > 0 && (
            <span translate="no" style={{ fontFamily: FI, fontSize: 12, color: 'rgba(255,255,255,0.55)' }}>
              / mes
            </span>
          )}
        </div>
        {/* Slot fijo para priceHint */}
        <div style={{ fontSize: 10.5, color: isStarter ? `${C.v}dd` : 'rgba(255,255,255,0.35)', minHeight: 16, marginBottom: 14 }}>
          {priceHint ?? ''}
        </div>

        {/* Tagline corta tipo "Ideal for..." */}
        <div style={{
          fontFamily: FI, fontSize: 12, color: 'rgba(255,255,255,0.65)',
          lineHeight: 1.45, marginBottom: 16,
        }}>
          {tagline}
        </div>

        {/* Barra de uso — solo en panel comerciante con plan actual */}
        {showUsageBar && (
          <div style={{
            marginBottom: 14,
            background: 'rgba(255,255,255,0.04)',
            border: '1px solid rgba(255,255,255,0.06)',
            borderRadius: 10, padding: '9px 11px',
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10.5, color: 'rgba(255,255,255,0.55)', marginBottom: 6 }}>
              <span>Clientes usados</span>
              <span style={{ fontFamily: FN, fontWeight: 700, color: C.white }}>{clientCount} / {planLimit}</span>
            </div>
            <div style={{ height: 3, borderRadius: 3, background: 'rgba(255,255,255,0.08)' }}>
              <div style={{
                height: '100%',
                width: `${Math.min(100, (clientCount / planLimit) * 100)}%`,
                background: clientCount >= planLimit
                  ? '#f87444'
                  : clientCount >= planLimit * .8
                    ? C.o
                    : (isStarter ? C.v : def.color),
                borderRadius: 3, transition: 'width .4s',
              }} />
            </div>
          </div>
        )}

        {/* Lista de features con check en círculo sutil */}
        <ul style={{
          margin: '0 0 18px', padding: 0, listStyle: 'none',
          display: 'flex', flexDirection: 'column', gap: 8, flex: 1,
        }}>
          {features.map(f => (
            <li key={f} style={{
              display: 'flex', alignItems: 'flex-start', gap: 8,
              fontFamily: FI, fontSize: 12,
              color: 'rgba(255,255,255,0.80)',
              lineHeight: 1.4,
            }}>
              {/* Tilde con relleno violeta sólido en las 3 cards (FREE / STARTER /
                  PRO) — refuerza identidad de marca y sube contraste. Antes era
                  círculo violeta a 15% opacidad con check violeta encima, casi
                  invisible. Ahora es círculo violeta sólido + check blanco
                  sobre él. */}
              <span style={{
                width: 16, height: 16, borderRadius: '50%',
                background: '#7131E1',
                display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                flexShrink: 0, marginTop: 1,
                boxShadow: `0 2px 6px ${C.v}55`,
              }}>
                <Check size={9} color="#fff" strokeWidth={3.5} />
              </span>
              <span>{f}</span>
            </li>
          ))}
        </ul>

        {/* CTA — pill ancho al fondo. STARTER pintado violeta sólido,
            FREE/PRO en gris oscuro neutro estilo referencia. */}
        {(() => {
          // Determina texto y handler según contexto (home / panel)
          let label = null
          let handler = null
          let active = !isCurrent

          if (isCurrent) {
            label = '✓ Plan activo'
            active = false
          } else if (onUpgrade && isUpgrade) {
            label = cta || `Activar ${def.label}`
            handler = () => onUpgrade(key)
          } else if (onUpgrade && !isUpgrade && currentPlan) {
            label = `Cambiar a ${def.label}`
            handler = () => onUpgrade(key)
          } else if (onCTA && cta) {
            label = cta
            handler = onCTA
          }

          if (!label) return null

          return (
            <button
              type="button"
              disabled={!active}
              onClick={handler || undefined}
              onMouseEnter={(e) => { if (active && !isStarter) e.currentTarget.style.background = 'rgba(255,255,255,0.10)' }}
              onMouseLeave={(e) => { if (active && !isStarter) e.currentTarget.style.background = 'rgba(255,255,255,0.06)' }}
              style={{
                width: '100%',
                padding: '11px 14px',
                borderRadius: 12,
                fontFamily: FN,
                fontSize: 12, fontWeight: 700,
                letterSpacing: '.005em',
                cursor: active ? 'pointer' : 'default',
                border: isStarter && active
                  ? 'none'
                  : '1px solid rgba(255,255,255,0.10)',
                background: !active
                  ? 'rgba(255,255,255,0.03)'
                  : isStarter
                    ? C.v
                    : 'rgba(255,255,255,0.06)',
                color: !active
                  ? 'rgba(255,255,255,0.45)'
                  : isStarter
                    ? '#fff'
                    : C.pearl,
                boxShadow: (isStarter && active)
                  ? `0 10px 30px -8px ${C.v}99, inset 0 1px 0 rgba(255,255,255,.18)`
                  : 'none',
                transition: 'background .2s, transform .15s, box-shadow .2s',
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8,
              }}
            >
              {label}
            </button>
          )
        })()}
      </div>
    )
  }

  return (
    <div style={isMobile
      ? { display:'flex', flexDirection:'column', gap:18 }
      : { display:'grid', gridTemplateColumns:'repeat(3, 1fr)', gap:20, alignItems:'stretch' }
    }>
      {PLAN_LIST.map(plan => renderCard(plan))}
    </div>
  )
}

function GradLine() {
  return <div style={{ height:2, background:G, borderRadius:99 }} />
}

function CoverImg({ src, height, children, style:s={} }) {
  const [hov, setHov] = useState(false)
  return (
    <div style={{ position:'relative', height, overflow:'hidden', ...s }}
      onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)}>
      <img src={src} alt="" style={{ width:'100%', height:'100%', objectFit:'cover', filter:'brightness(.65) saturate(1.3)', transform:hov?'scale(1.04)':'scale(1)', transition:'transform 150ms ease' }} />
      <div style={{ position:'absolute', inset:0, background:'rgba(113,49,225,0.08)', mixBlendMode:'color', pointerEvents:'none' }} />
      <div style={{ position:'absolute', inset:0, background:`linear-gradient(to bottom,rgba(13,8,24,.05) 0%,rgba(13,8,24,.85) 80%,${C.bg} 100%)`, pointerEvents:'none' }} />
      {children}
    </div>
  )
}

function FloatCover({ src, size=92 }) {
  return (
    <div style={{ width:size, height:size, borderRadius:'50%', overflow:'hidden', flexShrink:0, boxShadow:`0 12px 34px rgba(0,0,0,.65), 0 0 0 2.5px ${C.card}, 0 0 0 4.5px ${C.v}55` }}>
      <img src={src || 'https://images.unsplash.com/photo-1509042239860-f550ce710b93?w=400&q=70'} alt="" style={{ width:'100%', height:'100%', objectFit:'cover', filter:'brightness(.85) saturate(1.2)' }} />
    </div>
  )
}

function Spinner() {
  return <div style={{ width:32, height:32, border:`3px solid ${C.rim}`, borderTop:`3px solid ${C.v}`, borderRadius:'50%', animation:'spin 1s linear infinite', margin:'40px auto' }} />
}

// ─── BENEFIX LOADER ───────────────────────────────────────────────────────────
function BenefixLoader({ size = 80 }) {
  return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'center' }}>
      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64" fill="none" width={size} height={size}>
        <style>{`@keyframes bf-snake{to{stroke-dashoffset:-120.6}}.bf-p{stroke-dasharray:55 66;stroke-dashoffset:0;animation:bf-snake 3s linear infinite}`}</style>
        <defs>
          <linearGradient id="bfg" x1="0" y1="0" x2="1" y2="1">
            <stop offset="0%" stopColor="#7131E1" />
            <stop offset="55%" stopColor="#c026d3" />
            <stop offset="100%" stopColor="#ec4899" />
          </linearGradient>
        </defs>
        <path className="bf-p"
          d="M 32 32 C 32 20, 12 20, 12 32 C 12 44, 32 44, 32 32 C 32 20, 52 20, 52 32 C 52 44, 32 44, 32 32 Z"
          stroke="url(#bfg)" strokeWidth="6" strokeLinecap="round" strokeLinejoin="round" fill="none"
        />
      </svg>
    </div>
  )
}

// ─── LOADING SCREEN (primera visita por sesión) ───────────────────────────────
function LoadingScreen({ onComplete }) {
  const [count,     setCount]     = useState(0)
  const [wordIndex, setWordIndex] = useState(0)
  const WORDS = ['Sumando', 'Canjeando', 'Fidelizando']

  useEffect(() => {
    const duration = 2500
    const t0 = performance.now()
    let raf
    const tick = now => {
      const p = Math.min((now - t0) / duration, 1)
      const e = 1 - Math.pow(1 - p, 3)
      setCount(Math.floor(e * 100))
      if (p < 1) { raf = requestAnimationFrame(tick) }
      else { setTimeout(onComplete, 400) }
    }
    raf = requestAnimationFrame(tick)
    return () => cancelAnimationFrame(raf)
  }, [onComplete])

  useEffect(() => {
    const iv = setInterval(() => setWordIndex(i => (i + 1) % WORDS.length), 800)
    return () => clearInterval(iv)
  }, [])

  return (
    <div style={{ position:'fixed', inset:0, zIndex:9999, background:'#0a0a0f', display:'flex', flexDirection:'column', overflow:'hidden' }}>
      {/* Blobs */}
      <div style={{ position:'absolute', top:'-20%', left:'-10%', width:'60vw', height:'60vw', borderRadius:'50%', background:'radial-gradient(circle, rgba(139,92,246,0.30) 0%, transparent 70%)', filter:'blur(80px)', pointerEvents:'none' }} />
      <div style={{ position:'absolute', bottom:'-20%', right:'-10%', width:'50vw', height:'50vw', borderRadius:'50%', background:'radial-gradient(circle, rgba(236,72,153,0.25) 0%, transparent 70%)', filter:'blur(80px)', pointerEvents:'none' }} />

      {/* Logo */}
      <div style={{ padding:'24px', opacity:0.5 }}><Logo /></div>

      {/* Palabras rotativas */}
      <div style={{ flex:1, display:'flex', alignItems:'center', justifyContent:'center' }}>
        <div style={{ position:'relative', height:96, width:'100%', overflow:'hidden', textAlign:'center' }}>
          {WORDS.map((word, i) => (
            <span key={word} style={{
              position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center',
              fontFamily: FN, fontSize:'clamp(40px,8vw,72px)', fontWeight:900, letterSpacing:'-0.03em',
              background:'#7131E1',
              WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent',
              opacity:    i === wordIndex ? 1 : 0,
              transform:  i === wordIndex ? 'translateY(0)' : 'translateY(28px)',
              transition: 'opacity 0.45s ease, transform 0.45s ease',
              pointerEvents:'none',
            }}>
              {word}
            </span>
          ))}
        </div>
      </div>

      {/* Contador + barra */}
      <div style={{ padding:'20px 24px 32px' }}>
        <div style={{ textAlign:'right', marginBottom:12 }}>
          <span style={{
            fontFamily:FN, fontWeight:900, fontSize:'clamp(52px,10vw,80px)',
            fontVariantNumeric:'tabular-nums', letterSpacing:'-0.04em',
            background:'linear-gradient(135deg,#fff,rgba(255,255,255,0.45))',
            WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent',
          }}>
            {String(count).padStart(3, '0')}
          </span>
        </div>
        <div style={{ height:3, background:'rgba(255,255,255,0.10)', borderRadius:99, overflow:'hidden' }}>
          <div style={{
            height:'100%', borderRadius:99,
            background:'#7131E1',
            boxShadow:'0 0 20px rgba(168,85,247,0.55)',
            width:`${count}%`,
            transition:'width 80ms linear',
          }} />
        </div>
      </div>
    </div>
  )
}

function FullscreenLoader({ message }) {
  return (
    <div style={{ position:'fixed', inset:0, zIndex:9990, background:'#000', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center' }}>
      <div style={{ position:'absolute', top:'-20%', left:'-10%', width:'60vw', height:'60vw', borderRadius:'50%', background:'radial-gradient(circle, rgba(139,92,246,0.30) 0%, transparent 70%)', filter:'blur(80px)', pointerEvents:'none' }} />
      <div style={{ position:'absolute', bottom:'-20%', right:'-10%', width:'50vw', height:'50vw', borderRadius:'50%', background:'radial-gradient(circle, rgba(236,72,153,0.25) 0%, transparent 70%)', filter:'blur(80px)', pointerEvents:'none' }} />
      <BenefixLoader size={100} />
      {message && <p style={{ fontFamily:FI, fontSize:13, color:'rgba(255,255,255,0.50)', marginTop:24, margin:'24px 0 0' }}>{message}</p>}
    </div>
  )
}

// ─── NAVBAR ───────────────────────────────────────────────────────────────────
function Navbar({ setView, cityName, user, profile, commerce, onLogin, onLogout, currentView, clientTab, onOwnerProfile, activeContext, onContextChange, showContextSwitch }) {
  const role = profile?.role || 'client'
  // userIntent — capturado en el step de Intent post-OAuth. Si el user
  // explícitamente eligió 'client', escondemos los botones del kit dueño
  // (Eye + Store) aunque tenga rol commerce_owner. Eso permite que un
  // user que abrió un comercio pero quiere usar la app como cliente NO
  // vea la chrome de panel comerciante en el navbar global.
  // - undefined/null → tratar como NO opted-in: mostrar botones si role
  //   es commerce_owner (legacy compat).
  // - 'client'        → ocultar botones del kit dueño.
  // - 'merchant'/'both' → mostrar botones (sin importar role).
  const userIntent     = profile?.user_intent || null
  const showOwnerKit   = role === 'commerce_owner' && userIntent !== 'client'

  const [roleAskerOpen, setRoleAskerOpen] = useState(false) // legacy, no se usa
  const [dropdownOpen, setDropdownOpen] = useState(false)
  const [dropdownRect, setDropdownRect] = useState(null)
  const dropdownWrapRef  = useRef(null)
  const dropdownPortalRef = useRef(null)

  useEffect(() => {
    if (!dropdownOpen) return
    function handleOutside(e) {
      const inBtn    = dropdownWrapRef.current?.contains(e.target)
      const inPortal = dropdownPortalRef.current?.contains(e.target)
      if (!inBtn && !inPortal) setDropdownOpen(false)
    }
    document.addEventListener('mousedown', handleOutside)
    document.addEventListener('touchstart', handleOutside)
    return () => {
      document.removeEventListener('mousedown', handleOutside)
      document.removeEventListener('touchstart', handleOutside)
    }
  }, [dropdownOpen])

  // ── Scroll-aware: navbar transparente al tope, opaco con blur al scrollear ─
  // Threshold 50px: arriba el navbar queda invisible (deja respirar al hero
  // del home), pero apenas el usuario empieza a scrollear se solidifica para
  // no superponerse con los títulos de las secciones siguientes.
  const [scrolled, setScrolled] = useState(false)
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 50)
    onScroll()
    window.addEventListener('scroll', onScroll, { passive: true })
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  // Estilos inline que sobrescriben la CSS class `.navbar-glass` (que tiene
  // bg + blur fijos). Inline gana, así controlamos la transición desde JS.
  const NAV_TRANSITION = {
    transition: 'background 220ms ease, backdrop-filter 220ms ease, border-color 220ms ease',
  }
  const NAV_SCROLL_STATE = scrolled
    ? {
        background: 'rgba(0, 0, 0, 0.72)',
        backdropFilter: 'blur(14px)',
        WebkitBackdropFilter: 'blur(14px)',
        borderBottom: '1px solid rgba(255,255,255,0.06)',
      }
    : {
        background: 'transparent',
        backdropFilter: 'none',
        WebkitBackdropFilter: 'none',
        borderBottom: '1px solid transparent',
      }

  // ── Shared style helpers ──────────────────────────────────────────────────
  // Botones dentro del contenedor glass: transparentes por defecto,
  // gradient G como "indicador" en el botón activo (mismo patrón que ClientBottomNav).
  const BTN = { position:'relative', zIndex:1, display:'flex', alignItems:'center', justifyContent:'center', width:34, height:34, borderRadius:9, flexShrink:0, transition:'background 220ms ease, box-shadow 220ms ease' }
  const NEUTRAL = { background:'transparent', border:'none' }
  // Activo = degradé de marca
  // Rebrand mayo 2026: violeta brand sólido (#7131E1) en lugar del
  // gradient orange→fucsia (G). Mantiene la lectura de "indicador
  // activo" sin contradecir la nueva identidad sólida.
  const GRAD_ACTIVE = { background:'#7131E1', border:'none', boxShadow:'0 2px 10px rgba(113,49,225,0.42)' }
  // Aliases legacy (mantenidos para compatibilidad de los call sites; ahora todos
  // los activos usan el mismo gradient)
  const QR_HINT = NEUTRAL
  const BUILDING_ACTIVE = GRAD_ACTIVE

  function bs(targetView /* , variant */) {
    return currentView === targetView ? GRAD_ACTIVE : NEUTRAL
  }
  function ic(targetView) {
    return currentView === targetView ? '#fff' : 'rgba(255,255,255,0.70)'
  }
  // Botón "Mi cuenta" se prende cuando el user está en CUALQUIER pestaña de
  // ClientView (Mi billetera / Premios / Historial / Mi QR / Cuenta). Todas
  // son parte del "área del cliente" desde el punto de vista del usuario,
  // así que tiene sentido que el ícono del navbar quede destacado mientras
  // navega entre ellas. El sub-nav abajo se encarga de marcar cuál tab está
  // activa adentro.
  const accountActive = currentView === 'client'
  const bsAccount     = accountActive ? GRAD_ACTIVE : NEUTRAL
  const icAccount     = accountActive ? '#fff' : 'rgba(255,255,255,0.70)'

  // Click en el icono "Mi cuenta": navega a ClientView en la pestaña Perfil.
  // Independiente de la vista actual (home, scanner, commerce-settings, etc.),
  // el ClientBottomNav del cliente queda visible con sus 4 pestañas (Mi
  // billetera, Premios, Historial, Perfil) y el sub-nav marca Perfil como
  // activa.
  function goToAccount() {
    // Tap en el ícono User → siempre lleva a "Mi billetera" (mis clubs).
    // Antes iba a Perfil/Cuenta — pero la billetera es el "home" del
    // cliente, donde tiene sus tarjetas y descubre clubes nuevos.
    window.dispatchEvent(new CustomEvent('benefix:navigate', {
      detail: { view: 'client', tab: 'mis clubs' },
    }))
  }

  const NAV = { position:'fixed', top:10, left:10, right:10, zIndex:200, borderRadius:14, height:52, display:'flex', alignItems:'center', justifyContent:'space-between' }

  // Para usuarios no autenticados el navbar es siempre opaco — el botón
  // "Entrar" tiene que ser legible en cualquier scroll y cualquier sección.
  const NAV_OPAQUE = {
    background: 'rgba(0, 0, 0, 0.72)',
    backdropFilter: 'blur(14px)',
    WebkitBackdropFilter: 'blur(14px)',
    borderBottom: '1px solid rgba(255,255,255,0.06)',
  }

  // ── No logged-in user ─────────────────────────────────────────────────────
  if (!user) return (
    <>
      <nav className="navbar-glass" style={{ ...NAV, ...NAV_TRANSITION, ...NAV_OPAQUE, padding:'0 20px' }}>
        <div style={{ cursor:'pointer' }} onClick={() => setView('home')}><Logo /></div>
        <div style={{ display:'flex', gap:8, alignItems:'center' }}>
          {cityName && <span style={{ fontSize:11, color:C.mist, padding:'4px 10px', borderRadius:99, background:C.bg3, border:`1px solid ${C.rim}`, display:'inline-flex', alignItems:'center', gap:4 }}><MapPin size={10} color={C.mist} strokeWidth={2} />{cityName}</span>}
          {/* Link "Registrarse" — texto plano sin botón visual. Dispara el
              mismo roleAsker que "Entrar" porque el OAuth de Google crea la
              cuenta automáticamente si el user no existe. La diferencia es
              de copy/mental model: el user que viene a registrarse busca
              "Registrarse" antes que "Entrar". */}
          <button
            onClick={() => onLogin && onLogin()}
            style={{
              background: 'transparent',
              border: 'none',
              color: 'rgba(255,255,255,0.78)',
              fontFamily: FN, fontSize: 13, fontWeight: 600,
              cursor: 'pointer',
              padding: '4px 6px',
              transition: 'color 160ms ease',
            }}
            onMouseEnter={e => { e.currentTarget.style.color = '#fff' }}
            onMouseLeave={e => { e.currentTarget.style.color = 'rgba(255,255,255,0.78)' }}
          >
            Registrarse
          </button>
          <GBtn sm onClick={() => onLogin && onLogin()}>Entrar</GBtn>
        </div>
      </nav>
    </>
  )

  // ── Logged-in user ────────────────────────────────────────────────────────
  const isMerchantDD = activeContext === 'merchant'
  const ddHeaderLabel = isMerchantDD
    ? (commerce?.name || 'Mi negocio')
    : (profile?.name || profile?.full_name || user?.email || 'Mi perfil')
  function DDItem({ icon: Icon, label, onClickItem, danger }) {
    return (
      <button
        onClick={() => { setDropdownOpen(false); onClickItem() }}
        style={{ display:'flex', alignItems:'center', gap:10, width:'100%', background:'none', border:'none', cursor:'pointer', padding:'10px 14px', borderRadius:10, color: danger ? '#f87444' : 'rgba(255,255,255,0.88)', fontFamily:FN, fontSize:13, fontWeight:500, textAlign:'left' }}
        onMouseEnter={e => { e.currentTarget.style.background = danger ? 'rgba(248,116,68,0.10)' : 'rgba(255,255,255,0.07)' }}
        onMouseLeave={e => { e.currentTarget.style.background = 'none' }}
      >
        <Icon size={15} strokeWidth={2} color={danger ? '#f87444' : '#A78BFA'} />
        {label}
      </button>
    )
  }

  return (
    <>
    <nav className="navbar-glass" style={{ ...NAV, ...NAV_TRANSITION, ...NAV_SCROLL_STATE, padding:'0 16px' }}>
      <div style={{ cursor:'pointer' }} onClick={() => setView('home')}><Logo /></div>
      {/* LEGACY NAVBAR — reemplazado por BottomNavV2 el 2026-05-03.
          Borrar despues de validar 1 sprint. Bloque original con kit
          dueno (Eye + Store + Scan + User + LogOut) movido al final del
          archivo en un comentario JSX si hace falta volver. Por ahora
          dejamos solo la ContextSwitchPill aca; el resto de la chrome
          de cuenta vive en el MoreSheet del BottomNavV2. */}
      <div style={{ display:'flex', gap:8, alignItems:'center' }}>
        {showContextSwitch && (
          <div id="benefix-context-switch">
            <ContextSwitchPill
              activeContext={activeContext}
              onChange={onContextChange}
              visible={true}
            />
          </div>
        )}
        {/* Avatar chip con dropdown — portal para escapar del overflow:hidden del nav */}
        <div ref={dropdownWrapRef}>
          <button
            title={profile?.name || profile?.full_name || 'Mi perfil'}
            onClick={() => {
              if (!dropdownOpen && dropdownWrapRef.current) {
                // Guardamos la posición del botón ANTES de abrir, para posicionar
                // el portal con position:fixed correctamente.
                const r = dropdownWrapRef.current.getBoundingClientRect()
                setDropdownRect({ top: r.bottom + 8, right: window.innerWidth - r.right })
              }
              setDropdownOpen(o => !o)
            }}
            style={{ display:'flex', alignItems:'center', gap:7, background:'rgba(255,255,255,0.08)', border:'1px solid rgba(255,255,255,0.12)', borderRadius:99, padding:'4px 10px 4px 4px', cursor:'pointer' }}
          >
            {profile?.avatar_url ? (
              <img src={profile.avatar_url} alt="" style={{ width:26, height:26, borderRadius:'50%', objectFit:'cover', flexShrink:0 }} />
            ) : (
              <div style={{ width:26, height:26, borderRadius:'50%', background:'#7131E1', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                <span style={{ fontFamily:FN, fontSize:12, fontWeight:700, color:'#fff' }}>
                  {(profile?.name || profile?.full_name || user?.email || '?')[0].toUpperCase()}
                </span>
              </div>
            )}
            <span style={{ fontFamily:FN, fontSize:12, fontWeight:600, color:'rgba(255,255,255,0.85)', maxWidth:80, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
              {(profile?.name || profile?.full_name || user?.email || '').split(' ')[0]}
            </span>
          </button>
        </div>
      </div>
      {false && (
      <div className="liquid-glass-strong" style={{ position:'relative', display:'flex', gap:3, alignItems:'center', borderRadius:12, padding:4, overflow:'hidden' }}>

        {role === 'admin' && (<>
          <button title="Panel admin" onClick={() => setView('admin')}
            style={{ ...BTN, ...bs('admin'), cursor: currentView==='admin' ? 'default' : 'pointer' }}>
            <LayoutDashboard size={16} color={ic('admin')} />
          </button>
          <button title="Mi cuenta" onClick={goToAccount}
            style={{ ...BTN, ...bsAccount, cursor: 'pointer' }}>
            <User size={16} color={icAccount} />
          </button>
          <button title="Salir" onClick={onLogout} style={{ ...BTN, ...NEUTRAL, cursor:'pointer' }}>
            <DoorOpen size={16} color="rgba(255,255,255,0.70)" />
          </button>
        </>)}

        {showOwnerKit && (<>
          <button title="Escanear QR" onClick={currentView==='scanner' ? undefined : () => setView('scanner')}
            style={{ ...BTN, ...bs('scanner','qr'), cursor: currentView==='scanner' ? 'default' : 'pointer' }}>
            <ScanLine size={16} color={ic('scanner')} strokeWidth={2} />
          </button>
          {/* Eye + Store: íconos "hermanados" del dueño. Comparten paleta violeta
              tanto en estado inactivo (icono violeta sin relleno, fondo neutro)
              como en activo (fondo violeta sólido, icono blanco). Eso los
              distingue visualmente de los demás íconos del navbar (Scanner /
              User / Logout) que usan el gradiente naranja-violeta de marca,
              y le indica al user que son funciones específicas del modo dueño. */}
          {(() => {
            const eyeActive   = currentView === 'commerce'
            const storeActive = currentView === 'commerce-settings'
            // Rebrand mayo 2026: violeta brand sólido (#7131E1) en
            // lugar del gradient violeta-violeta. Misma intencion: marcar
            // el icono activo del kit duenio con glow brand, ícono blanco.
            const VIOLET_ACTIVE = {
              background: '#7131E1',
              border: 'none',
              boxShadow: '0 2px 10px rgba(113,49,225,0.55)',
            }
            return (
              <>
                <button title="Vista pública de mi club" onClick={onOwnerProfile}
                  style={{ ...BTN, ...(eyeActive ? VIOLET_ACTIVE : NEUTRAL), cursor: 'pointer' }}>
                  <Eye size={16} color={eyeActive ? '#fff' : 'rgba(189,75,248,0.85)'} strokeWidth={2} />
                </button>
                <button title="Mi Negocio"
                  onClick={() => {
                    if (currentView !== 'commerce-settings') setView('commerce-settings')
                    window.dispatchEvent(new CustomEvent('benefix:merchant-intent'))
                  }}
                  style={{ ...BTN, ...(storeActive ? VIOLET_ACTIVE : NEUTRAL), cursor: 'pointer' }}>
                  <Store size={16} color={storeActive ? '#fff' : 'rgba(189,75,248,0.85)'} strokeWidth={2} />
                </button>
              </>
            )
          })()}
          <button title="Mi cuenta" onClick={goToAccount}
            style={{ ...BTN, ...bsAccount, cursor: 'pointer' }}>
            <User size={16} color={icAccount} strokeWidth={2} />
          </button>
          <button title="Cerrar sesión" onClick={onLogout} style={{ ...BTN, ...NEUTRAL, cursor:'pointer' }}>
            <LogOut size={16} color="rgba(255,255,255,0.70)" strokeWidth={2} />
          </button>
        </>)}

        {/* Branch "cliente" — abarca:
            - role === 'client' (no tiene comercios)
            - role === 'commerce_owner' pero user_intent === 'client'
              (el dueño explícitamente eligió usar la app como cliente
              y queremos respetarle eso ocultando el kit dueño).
            En cualquier caso, sin Eye + Store, sin admin. */}
        {role !== 'admin' && !showOwnerKit && (<>
          <button title="Escanear QR" onClick={currentView==='scanner' ? undefined : () => setView('scanner')}
            style={{ ...BTN, ...bs('scanner','qr'), cursor: currentView==='scanner' ? 'default' : 'pointer' }}>
            <ScanLine size={16} color={ic('scanner')} strokeWidth={2} />
          </button>
          <button title="Mi cuenta" onClick={goToAccount}
            style={{ ...BTN, ...bsAccount, cursor: 'pointer' }}>
            <User size={16} color={icAccount} strokeWidth={2} />
          </button>
          <button title="Cerrar sesión" onClick={onLogout} style={{ ...BTN, ...NEUTRAL, cursor:'pointer' }}>
            <LogOut size={16} color="rgba(255,255,255,0.70)" strokeWidth={2} />
          </button>
        </>)}

      </div>
      )}
    </nav>
    {dropdownOpen && dropdownRect && typeof document !== 'undefined' && createPortal(
      <div ref={dropdownPortalRef} style={{ position:'fixed', top: dropdownRect.top, right: dropdownRect.right, minWidth:192, background:'rgba(12,8,24,0.96)', backdropFilter:'blur(20px)', WebkitBackdropFilter:'blur(20px)', border:'1px solid rgba(255,255,255,0.12)', borderRadius:14, padding:6, zIndex:9999, boxShadow:'0 12px 40px rgba(0,0,0,0.60)' }}>
        <button
          onClick={() => { setDropdownOpen(false); isMerchantDD ? setView('commerce-settings') : undefined }}
          style={{ display:'block', width:'100%', textAlign:'left', background:'none', border:'none', cursor: isMerchantDD ? 'pointer' : 'default', padding:'10px 14px 8px', borderBottom:'1px solid rgba(255,255,255,0.08)', marginBottom:4 }}
          onMouseEnter={e => { if (isMerchantDD) e.currentTarget.style.background = 'rgba(255,255,255,0.05)' }}
          onMouseLeave={e => { e.currentTarget.style.background = 'none' }}
        >
          <div style={{ fontFamily:FN, fontSize:13, fontWeight:600, color:'rgba(255,255,255,0.88)', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
            {ddHeaderLabel}
          </div>
          <div style={{ fontFamily:FI, fontSize:11, color:'rgba(255,255,255,0.35)', marginTop:2, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
            {user?.email}
          </div>
        </button>
        {isMerchantDD ? (<>
          <DDItem icon={Eye} label="Ver perfil público" onClickItem={() => {
            if (commerce?.slug) { window.location.href = `/club/${commerce.slug}?edit=1` }
            else { setDropdownOpen(false); setView('commerce-settings') }
          }} />
          <DDItem icon={LogOut} label="Cerrar sesión" onClickItem={() => onLogout?.()} danger />
        </>) : (<>
          <DDItem icon={Home} label="Mis clubes" onClickItem={() => {
            window.dispatchEvent(new CustomEvent('benefix:navigate', { detail: { view:'client', tab:'mis clubs' } }))
          }} />
          <DDItem icon={LogOut} label="Cerrar sesión" onClickItem={() => onLogout?.()} danger />
        </>)}
      </div>,
      document.body
    )}
    </>
  )
}

