// ─── BENEFICIO WORD — entrance blur + continuous fuchsia shimmer ──────────────
function BeneficioWord({ delay = 0 }) {
  const [show, setShow] = useState(false)
  const ref = useRef(null)

  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setShow(true); obs.disconnect() } },
      { threshold: 0.1 }
    )
    if (ref.current) obs.observe(ref.current)
    return () => obs.disconnect()
  }, [])

  return (
    <span ref={ref} style={{
      display: 'inline-block',
      opacity:   show ? 1 : 0,
      filter:    show ? 'blur(0px)' : 'blur(10px)',
      transform: show ? 'translateY(0)' : 'translateY(20px)',
      transition: `opacity 0.7s ease, filter 0.7s ease, transform 0.7s cubic-bezier(0.23,1,0.32,1)`,
      transitionDelay: `${delay}ms`,
      background: '#7131E1',
      backgroundSize: '300% 100%',
      WebkitBackgroundClip: 'text',
      WebkitTextFillColor: 'transparent',
      backgroundClip: 'text',
      textShadow: 'none',
    }}>
      beneficio.
    </span>
  )
}

// ─── BLUR TEXT ANIMATION ──────────────────────────────────────────────────────
// Pass `active` bool to control externally, or omit to use IntersectionObserver
function BlurText({ text, delay = 0, active }) {
  const words = text.split(' ')
  const [inView, setInView] = useState(false)
  const ref = useRef(null)

  useEffect(() => {
    if (active !== undefined) return
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setInView(true); obs.disconnect() } },
      { threshold: 0.1 }
    )
    if (ref.current) obs.observe(ref.current)
    return () => obs.disconnect()
  }, [])

  const show = active !== undefined ? active : inView
  return (
    <span ref={ref}>
      {words.map((word, i) => (
        <span key={i} style={{
          display:'inline-block', marginRight:'0.25em',
          opacity:   show ? 1 : 0,
          filter:    show ? 'blur(0px)' : 'blur(10px)',
          transform: show ? 'translateY(0)' : 'translateY(20px)',
          transition:`opacity 0.7s ease, filter 0.7s ease, transform 0.7s cubic-bezier(0.23,1,0.32,1)`,
          transitionDelay:`${delay + i * 100}ms`,
        }}>{word}</span>
      ))}
    </span>
  )
}

// ─── HERO SECTION ─────────────────────────────────────────────────────────────
function HeroSection({ setView, user, profile, onLogin }) {
  const [loaded, setLoaded] = useState(false)
  const isOwner = profile?.role === 'commerce_owner'

  // ──────────────────────────────────────────────────────────────────────────
  // Login redesign (abr 2026): los CTAs "Soy cliente" / "Soy comercio" del
  // landing manejan dos casos:
  //   • Usuario NO logueado → guardamos en sessionStorage el "rol" pretendido
  //     (`benefix:signupAs`) y disparamos handleLogin(). Después del callback
  //     OAuth, el boot flow lee ese flag y muestra MinimalSignupModal en el
  //     modo correspondiente, en lugar del OnboardingFlow viejo de 6 pasos.
  //   • Usuario logueado → ruteo directo a su panel (cliente o comerciante).
  //     Si es cliente y elige "Soy comercio", abrimos el modal merchant en
  //     línea (cross-rol) sin re-loguear.
  // Esto reemplaza el flujo anterior donde "Soy cliente" iba a /client y
  // "Soy comercio" iba a /register-commerce — eran dos destinos distintos
  // que confundían a usuarios nuevos antes de identificarse.
  function handleSignupCTA(role) {
    if (!user) {
      try { sessionStorage.setItem('benefix:signupAs', role) } catch {}
      onLogin && onLogin()
      return
    }
    if (role === 'client') {
      setView(isOwner ? 'commerce-settings' : 'client')
      return
    }
    // role === 'merchant'
    if (isOwner) { setView('commerce-settings'); return }
    // Usuario logueado pero sin negocio → abrimos modal merchant inline.
    try { sessionStorage.setItem('benefix:signupAs', 'merchant') } catch {}
    window.dispatchEvent(new CustomEvent('benefix:open-signup', { detail: { mode: 'merchant' } }))
  }

  useEffect(() => {
    const t = setTimeout(() => setLoaded(true), 60)
    return () => clearTimeout(t)
  }, [])

  const TRUST = [
    { Icon: Coffee,          label: 'Cafeterías'   },
    { Icon: Scissors,        label: 'Barberías'    },
    { Icon: UtensilsCrossed, label: 'Restaurantes' },
    { Icon: ShoppingBag,     label: 'Tiendas'      },
    { Icon: Dumbbell,        label: 'Gimnasios'    },
    { Icon: Sparkles,        label: 'Peluquerías'  },
    { Icon: IceCream,        label: 'Heladerías'   },
    { Icon: Croissant,       label: 'Panaderías'   },
    { Icon: Flower2,         label: 'Spa'          },
    { Icon: Car,             label: 'Lavaderos'    },
    { Icon: Pizza,           label: 'Pizzerías'    },
    { Icon: PawPrint,        label: 'Veterinarias' },
  ]

  return (
    <section className="animated-gradient-bg" style={{ position:'relative', minHeight:'100vh', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', overflow:'hidden', padding:'80px 24px 48px' }}>

      {/* Background blobs */}
      <div style={{ position:'absolute', top:'-20%', left:'-10%', width:'60vw', height:'60vw', borderRadius:'50%', background:'radial-gradient(circle, rgba(139,92,246,0.40) 0%, transparent 70%)', filter:'blur(80px)', pointerEvents:'none', zIndex:0 }} />
      <div style={{ position:'absolute', bottom:'-20%', right:'-10%', width:'50vw', height:'50vw', borderRadius:'50%', background:'radial-gradient(circle, rgba(236,72,153,0.35) 0%, transparent 70%)', filter:'blur(80px)', pointerEvents:'none', zIndex:0 }} />
      <div style={{ position:'absolute', top:'40%', right:'-5%', width:'35vw', height:'35vw', borderRadius:'50%', background:'radial-gradient(circle, rgba(168,85,247,0.20) 0%, transparent 70%)', filter:'blur(60px)', pointerEvents:'none', zIndex:0 }} />

      {/* Content */}
      <div style={{ position:'relative', zIndex:1, textAlign:'center', maxWidth:780, width:'100%' }}>

        {/* Animated badge */}
        <div style={{
          display:'inline-flex', alignItems:'center', gap:8, borderRadius:9999,
          padding:'4px 6px', marginBottom:40,
          opacity: loaded ? 1 : 0,
          transform: loaded ? 'translateY(0)' : 'translateY(20px)',
          transition:'opacity 0.7s ease 0.2s, transform 0.7s ease 0.2s',
        }} className="liquid-glass">
          <span style={{ background:G, color:'#fff', fontSize:11, fontWeight:700, fontFamily:FN, padding:'4px 12px', borderRadius:9999, letterSpacing:'.04em' }}>
            Nuevo
          </span>
          <span style={{ fontSize:13, color:'rgba(255,255,255,0.65)', fontFamily:FI, paddingRight:10 }}>
            La forma más fácil de fidelizar
          </span>
        </div>

        {/* Headline */}
        <h1 style={{ fontFamily:FN, fontWeight:900, fontSize:'clamp(38px,7vw,80px)', lineHeight:1.05, letterSpacing:'-.03em', margin:'0 0 28px', color:'#fff' }}>
          <span style={{ display:'block' }}>
            <BlurText text="Cada visita" delay={300} />
          </span>
          <span style={{ display:'block' }}>
            <BlurText text="te acerca a tu" delay={500} />
          </span>
          <span style={{ display:'block' }}>
            <BeneficioWord delay={700} />
          </span>
        </h1>

        {/* Subtitle */}
        <p style={{
          fontSize:'clamp(15px,1.8vw,19px)', color:'rgba(255,255,255,0.58)', maxWidth:520, margin:'0 auto 44px', lineHeight:1.75, fontFamily:FI,
          opacity: loaded ? 1 : 0,
          filter:  loaded ? 'blur(0)' : 'blur(10px)',
          transform: loaded ? 'translateY(0)' : 'translateY(20px)',
          transition:'opacity 0.7s ease 1s, filter 0.7s ease 1s, transform 0.7s ease 1s',
        }}>
          Sistema de fidelización para comercios. Tus clientes suman puntos
          y canjean premios con un simple QR.
        </p>

        {/* CTAs */}
        <div style={{
          display:'flex', flexWrap:'wrap', alignItems:'center', justifyContent:'center', gap:14,
          opacity: loaded ? 1 : 0,
          transform: loaded ? 'translateY(0)' : 'translateY(20px)',
          transition:'opacity 0.7s ease 1.2s, transform 0.7s ease 1.2s',
        }}>
          <Btn onClick={() => handleSignupCTA('client')}>
            Soy cliente <ArrowRight size={16} strokeWidth={2.5} />
          </Btn>
          <Btn variant="ghost" onClick={() => handleSignupCTA('merchant')}>
            Soy comercio <ArrowRight size={16} strokeWidth={2.5} />
          </Btn>
        </div>

        {/* Trust badges — marquee infinito */}
        <div style={{
          marginTop:64,
          opacity: loaded ? 1 : 0,
          transition:'opacity 0.7s ease 1.5s',
        }}>
          <p style={{ fontSize:12, color:'rgba(255,255,255,0.46)', fontFamily:FI, marginBottom:20, letterSpacing:'.04em' }}>
            Más de 500 comercios confían en nosotros
          </p>
          <div
            aria-label="Rubros de comercios que usan Benefix"
            style={{
              overflow: 'hidden',
              WebkitMaskImage: 'linear-gradient(to right, transparent 0%, black 60px, black calc(100% - 60px), transparent 100%)',
              maskImage: 'linear-gradient(to right, transparent 0%, black 60px, black calc(100% - 60px), transparent 100%)',
            }}
          >
            <div className="trust-marquee">
              {TRUST.map(({ Icon, label }) => (
                <div key={label} className="trust-marquee-item">
                  <Icon size={24} color="#7131E1" strokeWidth={1.5} />
                  <span>{label}</span>
                </div>
              ))}
              {/* Duplicado para loop seamless — oculto a lectores de pantalla */}
              {TRUST.map(({ Icon, label }) => (
                <div key={`d-${label}`} className="trust-marquee-item" aria-hidden="true">
                  <Icon size={24} color="#7131E1" strokeWidth={1.5} />
                  <span>{label}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

      </div>

      {/* Scroll indicator */}
      <div style={{
        position:'absolute', bottom:32, left:'50%', transform:'translateX(-50%)', zIndex:1,
        display:'flex', flexDirection:'column', alignItems:'center', gap:8,
        opacity: loaded ? 1 : 0,
        transition:'opacity 1s ease 2s',
      }}>
        <span style={{ fontFamily:FN, fontSize:10, color:'rgba(255,255,255,0.35)', letterSpacing:'0.15em', textTransform:'uppercase' }}>Scroll</span>
        <div style={{ width:1, height:48, background:'rgba(255,255,255,0.15)', position:'relative', overflow:'hidden', borderRadius:1 }}>
          <div className="scroll-light" style={{ position:'absolute', top:0, left:0, width:'100%', height:16, background:'#7131E1', borderRadius:1 }} />
        </div>
      </div>

      {/* Bottom fade into next section */}
      <div style={{ position:'absolute', bottom:0, left:0, right:0, height:120, background:'linear-gradient(to bottom, transparent, #0a0a0f)', pointerEvents:'none', zIndex:2 }} />
    </section>
  )
}

// ─── COUNT-UP ──────────────────────────────────────────────────────────────────
function CountUp({ end, duration = 2000, suffix = '', prefix = '', decimals = 0 }) {
  const [count,     setCount]     = useState(0)
  const [isVisible, setIsVisible] = useState(false)
  const ref = useRef(null)

  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setIsVisible(true); obs.disconnect() } },
      { threshold: 0.3 }
    )
    if (ref.current) obs.observe(ref.current)
    return () => obs.disconnect()
  }, [])

  useEffect(() => {
    if (!isVisible) return
    const factor = Math.pow(10, decimals)
    const target = Math.round(end * factor)
    let startTime
    function step(ts) {
      if (!startTime) startTime = ts
      const progress = Math.min((ts - startTime) / duration, 1)
      const eased = 1 - Math.pow(1 - progress, 3)
      setCount(Math.round(eased * target))
      if (progress < 1) requestAnimationFrame(step)
    }
    requestAnimationFrame(step)
  }, [isVisible, end, duration, decimals])

  const factor = Math.pow(10, decimals)
  const display = decimals > 0
    ? (count / factor).toFixed(decimals)
    : count.toLocaleString('es-AR')

  return <span ref={ref}>{prefix}{display}{suffix}</span>
}

// ─── FEATURES ──────────────────────────────────────────────────────────────────
// Reemplaza la vieja StatsSection ("500+ comercios, 15000+ clientes...") que
// mostraba números fabricados. Acá enumeramos funcionalidades CONCRETAS y
// reales del producto — eso convierte mejor que vanity metrics inventadas y
// además marca la diferencia con tarjetas de papel o apps genéricas.
//
// 6 cards en grid responsive (3 cols desktop / 2 tablet / 1 mobile). Cada
// feature tiene icon + título + descripción de 1-2 líneas. Los colores de los
// íconos siguen el código de marca: violeta = sistema/QR, fucsia = clientes,
// naranja = engagement, verde = analytics, ámbar = automatizaciones (PRO).
function FeaturesSection() {
  const features = [
    {
      Icon: QrCode,
      title: 'QR único del negocio',
      desc: 'Cada local tiene su QR personalizado. El cliente escanea, queda dentro del club. Cero tarjetas de papel que se pierden.',
      color: '#7131E1',
    },
    {
      Icon: Star,
      title: 'Estrellas o puntos',
      desc: 'Elegís el sistema que mejor te queda. Estrellas (1 por compra) para algo simple, o puntos (1 = $1) para algo flexible.',
      color: '#EC4899',
    },
    {
      Icon: Gift,
      title: 'Catálogo de premios',
      desc: 'El premio lo elegís vos: un café, un descuento, lo que vaya con tu local. El cliente lo canjea desde la tarjeta digital cuando llega.',
      color: '#F97316',
    },
    {
      Icon: Percent,
      title: 'Promos automáticas',
      desc: 'Cupón de descuento para la próxima visita, o doble puntos los días que vos elijas (lunes flojos, miércoles muertos). Lo configurás una vez y corre solo.',
      color: '#5B8DEF',
    },
    {
      Icon: BarChart2,
      title: 'Reportes y segmentación',
      desc: 'Mirá quién viene seguido, quién se enfrió y cuánto te facturan tus VIP. Filtrá por segmentos y exportá a Excel.',
      color: '#22E698',
    },
    {
      Icon: Bell,
      title: 'WhatsApp y notificaciones',
      desc: 'Mensajes de WhatsApp listos para mandar al cliente que hace tiempo no viene. Y notifs push cuando tiene un premio para canjear.',
      color: '#F5A623',
    },
  ]

  // ── Parallax scroll-driven sobre los íconos animados de cada card.
  // Reemplaza los keyframes infinitos `feature-icon-float-X` por un offset
  // que depende del progreso del scroll a través de la sección. Cada capa
  // toma un factor distinto (algunas se mueven más, otras menos, otras al
  // revés) para crear sensación de profundidad cuando el usuario scrollea.
  const sectionRef = useRef(null)
  const [scrollProgress, setScrollProgress] = useState(0)
  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current
      if (!el) return
      const rect = el.getBoundingClientRect()
      const center = (rect.top + rect.bottom) / 2
      const vh = window.innerHeight || 800
      // Progreso en unidades de "pantallas": 0 = sección centrada en viewport,
      // negativo = sección por encima, positivo = sección por debajo.
      // Cap a ±1.5 para que el movimiento no se vaya de la card.
      const p = (center - vh / 2) / vh
      setScrollProgress(Math.max(-1.5, Math.min(1.5, p)))
    }
    onScroll()
    window.addEventListener('scroll', onScroll, { passive: true })
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  // Factores de parallax (px de drift máximo por unidad de scrollProgress).
  // Mismas direcciones que los keyframes viejos para mantener la coherencia.
  const PARALLAX = {
    bg:       { x: -22, y: -28 },
    topLeft:  { x:  26, y:  20 },
    topRight: { x:  24, y: -26 },
    btmLeft:  { x: -28, y:  22 },
    btmRight: { x:  20, y:  18 },
    front:    { x:   0, y:  14 },
  }
  const fx = (key) => {
    const { x, y } = PARALLAX[key]
    return `translate(-50%, -50%) translate(${(scrollProgress * x).toFixed(1)}px, ${(scrollProgress * y).toFixed(1)}px)`
  }

  return (
    <section ref={sectionRef} className="section-secondary" style={{
      // Fondo negro puro — el dueño lo quiere así (no violeta oscuro,
      // no overlay de marca, solo negro plano).
      background: '#000',
      padding:'100px 20px',
      position:'relative',
      overflow:'hidden',
    }}>
      {/* Los íconos de cada card ya no usan keyframes infinitos: ahora se
          mueven con scroll-driven parallax (ver scrollProgress + fx() arriba).
          Los keyframes feature-icon-float-{a,b,c,d,front} siguen definidos en
          app/globals.css por si querés volver, pero ya no se referencian. */}
      <div style={{ maxWidth:1080, margin:'0 auto', position:'relative', zIndex:2 }}>
        <div style={{ textAlign:'center', marginBottom:18 }}>
          <span className="liquid-glass" style={{ display:'inline-block', borderRadius:99, padding:'7px 18px', fontSize:11, color:'rgba(255,255,255,0.65)', fontFamily:FN, fontWeight:600, letterSpacing:'.10em', textTransform:'uppercase' }}>Qué tiene Benefix</span>
        </div>
        {/* H2 con la misma escala y peso del headline del hero V2:
            clamp grande, weight 600 (no 900), letter-spacing negativo y
            line-height ajustado. Eso pega visualmente con "Tu club, tu marca." */}
        <h2 style={{ fontFamily:FN, fontSize:'clamp(28px, 5vw, 48px)', fontWeight:600, letterSpacing:'-0.03em', color:'#fff', textAlign:'center', marginBottom:18, lineHeight:1.05 }}>
          Tu club, <span style={{ fontStyle:'italic', fontWeight:500 }}>completo.</span>
        </h2>
        <p style={{ fontFamily:FI, fontSize:'clamp(14px, 1.7vw, 17px)', color:'rgba(255,255,255,0.70)', textAlign:'center', maxWidth:480, margin:'0 auto 56px', lineHeight:1.55 }}>
          Configuralo desde tu celular, en minutos.
        </p>
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit, minmax(280px, 1fr))', gap:16 }}>
          {features.map((f, i) => {
            const Icon = f.Icon
            return (
              <div
                key={i}
                className="liquid-glass"
                style={{
                  borderRadius:20,
                  padding:'28px 26px',
                  display:'flex', flexDirection:'column', gap:14,
                  position:'relative', overflow:'hidden',
                  transition:'transform 280ms cubic-bezier(0.22,1,0.36,1)',
                  // El borde gradient lo da .liquid-glass::before; no le
                  // sumamos otro border encima para no romperlo.
                }}
                onMouseEnter={(e) => { e.currentTarget.style.transform = 'translateY(-3px)' }}
                onMouseLeave={(e) => { e.currentTarget.style.transform = 'translateY(0)' }}
              >
                {/* Glow ambiental atrás del ícono — tinta el corner con
                    el color de la feature, ahora más sutil para no
                    competir con el chrome glass. */}
                <div style={{
                  position:'absolute', top:-40, left:-40,
                  width:160, height:160, borderRadius:'50%',
                  background:`radial-gradient(circle, ${f.color}28 0%, transparent 70%)`,
                  filter:'blur(24px)', pointerEvents:'none',
                }} />
                {/* Composición animada de íconos — ocupa toda la zona
                    superior de la card (ancho completo, alto 110px) en
                    vez del cuadradito chico de antes. Distribuyo 6
                    instancias del MISMO ícono a distintos tamaños,
                    opacidades y posiciones para llenar el área entera,
                    cada una con su propia animación de drift suave (6-11s)
                    que varía dirección + scale leves. Sin borde propio
                    en el contenedor — solo un overflow:hidden por si
                    alguna capa al expandirse roza el borde. */}
                <div style={{
                  width: '100%', height: 110,
                  position:'relative',
                  flexShrink: 0,
                  overflow: 'hidden',
                  marginBottom: 4,
                }}>
                  {/* Capa background — ícono más grande, casi imperceptible,
                      drift muy lento. Centrado, le da peso visual al medio.
                      will-change:transform fuerza al browser a usar la GPU
                      para compositar la animación, así no parpadea. */}
                  <Icon
                    size={104}
                    color={f.color}
                    strokeWidth={0.9}
                    style={{
                      position:'absolute', left:'50%', top:'50%',
                      transform: fx('bg'),
                      opacity: 0.08,
                      transition: 'transform 80ms linear',
                      willChange: 'transform',
                    }}
                  />
                  {/* Top-left mid-faded */}
                  <Icon
                    size={58}
                    color={f.color}
                    strokeWidth={1.2}
                    style={{
                      position:'absolute', left:'16%', top:'28%',
                      transform: fx('topLeft'),
                      opacity: 0.18,
                      transition: 'transform 80ms linear',
                      willChange: 'transform',
                    }}
                  />
                  {/* Top-right mid-faded */}
                  <Icon
                    size={54}
                    color={f.color}
                    strokeWidth={1.2}
                    style={{
                      position:'absolute', left:'84%', top:'32%',
                      transform: fx('topRight'),
                      opacity: 0.16,
                      transition: 'transform 80ms linear',
                      willChange: 'transform',
                    }}
                  />
                  {/* Bottom-left smaller */}
                  <Icon
                    size={42}
                    color={f.color}
                    strokeWidth={1.5}
                    style={{
                      position:'absolute', left:'26%', top:'74%',
                      transform: fx('btmLeft'),
                      opacity: 0.28,
                      transition: 'transform 80ms linear',
                      willChange: 'transform',
                    }}
                  />
                  {/* Bottom-right smaller */}
                  <Icon
                    size={40}
                    color={f.color}
                    strokeWidth={1.5}
                    style={{
                      position:'absolute', left:'74%', top:'72%',
                      transform: fx('btmRight'),
                      opacity: 0.26,
                      transition: 'transform 80ms linear',
                      willChange: 'transform',
                    }}
                  />
                  {/* Front — ícono central nítido con glow, marca dónde
                      vive el "ícono real" de la feature. Pulse leve sin
                      moverse de posición. */}
                  <Icon
                    size={40}
                    color={f.color}
                    strokeWidth={2.2}
                    style={{
                      position:'absolute', left:'50%', top:'50%',
                      transform: fx('front'),
                      zIndex: 2,
                      filter:`drop-shadow(0 0 14px ${f.color}cc)`,
                      transition: 'transform 80ms linear',
                      willChange: 'transform',
                    }}
                  />
                </div>
                <div style={{ fontFamily:FN, fontSize:17, fontWeight:600, color:'#fff', lineHeight:1.25, letterSpacing:'-.015em', position:'relative' }}>
                  {f.title}
                </div>
                <div style={{ fontFamily:FI, fontSize:13.5, color:'rgba(255,255,255,0.70)', lineHeight:1.6, position:'relative', fontWeight:400 }}>
                  {f.desc}
                </div>
              </div>
            )
          })}
        </div>
      </div>
    </section>
  )
}

// ─── HOW IT WORKS ──────────────────────────────────────────────────────────────
// Versión video-feature-grid: 3 cards con video de fondo full-bleed
// (autoplay, loop, muted) + overlay con número, kicker, título y párrafo.
// Layout asimétrico inspirado en landing pages tipo Nexora:
//   • Card 01: alto a la izquierda (col 1, span 2 filas)
//   • Card 02: ancho top-right (cols 2-3)
//   • Card 03: ancho bottom-right (cols 2-3)
// Mantiene la utilidad .liquid-glass del CSS global para el CTA.
// La función vieja (scroll-stacking con sticky cards y motifs decorativos
// CSS) la guardamos abajo como _HowItWorksSectionLegacy por si quisiéramos
// volver, pero la export por default es esta nueva.
function HowItWorksSection() {
  const HELV = "'Helvetica Neue', Helvetica, Arial, sans-serif"
  const CARD_BG = '#252B4C'

  // Hook a viewport size para ajustar layout (mobile = stack, desktop = grid asimétrico)
  const [isMobileLocal, setIsMobileLocal] = useState(false)
  useEffect(() => {
    const check = () => setIsMobileLocal(window.innerWidth < 768)
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  const cards = [
    {
      num: '01/',
      kicker: 'El cliente se suma',
      title: 'Tu QR vive\nen el mostrador',
      paragraph: 'El cliente saca el celular, escanea, y queda anotado en tu club.\nSin app que descargar.',
      videoSrc: 'https://d8j0ntlcm91z4.cloudfront.net/user_38xzZboKViGWJOttwIXH07lWA1P/hf_20260427_104605_2700410c-4303-4d44-a368-e1b8c84eca8c.mp4',
      // Layout: tall left
      gridArea: 'tall',
    },
    {
      num: '02/',
      kicker: 'Cada visita cuenta',
      title: 'El puntaje sube\nen vivo',
      paragraph: 'Cliente y dueño ven el balance al toque, desde el celular.',
      videoSrc: 'https://d8j0ntlcm91z4.cloudfront.net/user_38xzZboKViGWJOttwIXH07lWA1P/hf_20260427_104731_bfd355f7-1f84-4f81-ad88-52c2bca70bad.mp4',
      gridArea: 'topRight',
    },
    {
      num: '03/',
      kicker: 'Cuando hay saldo',
      title: 'Canjeás premios reales',
      paragraph: 'Café, descuento, postre — cada premio del catálogo\nse canjea por los puntos que el cliente acumuló.',
      videoSrc: 'https://d8j0ntlcm91z4.cloudfront.net/user_38xzZboKViGWJOttwIXH07lWA1P/hf_20260427_104758_e7d78f06-3700-4862-8c9b-595ed447e81a.mp4',
      gridArea: 'bottomRight',
    },
  ]

  // Render común para una card. children es el contenido del overlay
  // (relative, va por encima del video de fondo).
  function FeatureCard({ card, style, contentExtra }) {
    return (
      <div style={{
        background: CARD_BG,
        borderRadius: '1.25rem',
        position: 'relative',
        overflow: 'hidden',
        padding: '28px',
        display: 'flex',
        flexDirection: 'column',
        minHeight: 360,
        ...style,
      }}>
        {/* Video full-bleed de fondo, desaturado para que el overlay de
            marca tinte limpio. saturate(0.18) deja casi escala de grises
            pero conserva un toque de información cromática del original
            que no se ve plasta. brightness(0.85) baja un poco la luz
            para que el texto blanco quede legible. */}
        <video
          src={card.videoSrc}
          autoPlay
          muted
          loop
          playsInline
          preload="auto"
          style={{
            position: 'absolute',
            inset: 0,
            width: '100%',
            height: '100%',
            objectFit: 'cover',
            zIndex: 0,
            filter: 'saturate(0.18) brightness(0.85) contrast(1.08)',
          }}
        />
        {/* Overlay 1: tint de marca (gradient naranja → fucsia → violeta).
            mix-blend-mode 'overlay' aplica los colores de marca al video
            en escala de grises preservando los highlights y shadows del
            video original. Produce el "look Benefix": video tintado en
            los tres tonos de marca según la zona de luminosidad. */}
        <div style={{
          position: 'absolute',
          inset: 0,
          zIndex: 0,
          background: 'linear-gradient(135deg, rgba(254,80,0,0.85) 0%, rgba(236,72,153,0.80) 50%, rgba(189,75,248,0.85) 100%)',
          mixBlendMode: 'overlay',
          pointerEvents: 'none',
        }} />
        {/* Overlay 2: oscurecimiento sutil del bottom para legibilidad
            del texto (kicker, título, paragraph) que cae en la zona
            baja de las cards. */}
        <div style={{
          position: 'absolute',
          inset: 0,
          zIndex: 0,
          background: 'linear-gradient(180deg, rgba(0,0,0,0) 35%, rgba(0,0,0,0.45) 100%)',
          pointerEvents: 'none',
        }} />
        {/* Top row: número + kicker */}
        <div style={{
          position: 'relative', zIndex: 1,
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          fontSize: 14,
          color: 'rgba(255,255,255,0.60)',
          fontFamily: HELV,
          gap: 12,
        }}>
          {card.gridArea === 'topRight' ? (
            <>
              {/* Card 02 invierte: heading a la izquierda, número a la derecha */}
              <h2 style={{
                fontSize: 'clamp(20px, 2.4vw, 26px)',
                fontWeight: 500,
                color: '#fff',
                fontFamily: HELV,
                lineHeight: 1.15,
                whiteSpace: 'pre-line',
                margin: 0,
                maxWidth: '70%',
              }}>{card.title}</h2>
              <span>{card.num}</span>
            </>
          ) : (
            <>
              <span>{card.num}</span>
              <span>{card.kicker}</span>
            </>
          )}
        </div>

        {/* Spacer flex */}
        <div style={{ flex: 1, minHeight: card.gridArea === 'topRight' ? 192 : 24 }} />

        {/* Bottom block con título + paragraph (excepto card 02 que tiene heading arriba) */}
        {card.gridArea !== 'topRight' && (
          <div style={{ position: 'relative', zIndex: 1 }}>
            <h2 style={{
              fontSize: 'clamp(20px, 2.4vw, 26px)',
              fontWeight: 500,
              color: '#fff',
              fontFamily: HELV,
              lineHeight: 1.15,
              whiteSpace: 'pre-line',
              margin: 0,
            }}>{card.title}</h2>
            {card.paragraph && card.gridArea === 'tall' && (
              <>
                <div style={{ marginTop: 16, height: 1, width: '100%', background: 'rgba(255,255,255,0.20)' }} />
                <p style={{
                  marginTop: 16,
                  fontSize: 12,
                  color: 'rgba(255,255,255,0.70)',
                  fontFamily: HELV,
                  lineHeight: 1.55,
                  whiteSpace: 'pre-line',
                  margin: '16px 0 0',
                }}>{card.paragraph}</p>
              </>
            )}
            {card.paragraph && card.gridArea === 'bottomRight' && (
              <p style={{
                marginTop: 12,
                fontSize: 12,
                color: 'rgba(255,255,255,0.80)',
                fontFamily: HELV,
                lineHeight: 1.55,
                whiteSpace: 'pre-line',
                margin: '12px 0 0',
              }}>{card.paragraph}</p>
            )}
          </div>
        )}

        {/* Extra del fondo de la card (botón opcional) */}
        {contentExtra && (
          <div style={{ position: 'relative', zIndex: 1, marginTop: 24 }}>
            {contentExtra}
          </div>
        )}
      </div>
    )
  }

  return (
    <section style={{
      padding: '100px 24px',
      background: '#000',
      position: 'relative',
    }}>
      <div style={{ maxWidth: 1200, margin: '0 auto' }}>
        {/* Header de sección: kicker + título grande */}
        <div style={{
          marginBottom: 40,
          display: 'flex',
          flexDirection: isMobileLocal ? 'column' : 'row',
          alignItems: isMobileLocal ? 'flex-start' : 'flex-start',
          justifyContent: 'space-between',
          gap: 24,
        }}>
          <h2 style={{
            fontFamily: HELV,
            fontSize: 'clamp(24px, 4.2vw, 44px)',
            fontWeight: 400,
            letterSpacing: '-0.02em',
            color: '#fff',
            lineHeight: 1.1,
            margin: 0,
            maxWidth: 720,
          }}>
            Cómo funciona, sin vueltas.
            <span style={{ display: 'block', color: 'rgba(255,255,255,0.40)', marginTop: 8 }}>
              Del QR al canje, en tres movimientos.
            </span>
          </h2>
        </div>

        {/* Grid de cards: en mobile stack vertical, en desktop layout asimétrico */}
        <div style={isMobileLocal ? {
          display: 'flex',
          flexDirection: 'column',
          gap: 20,
        } : {
          display: 'grid',
          gridTemplateColumns: 'repeat(3, 1fr)',
          gridTemplateRows: 'auto auto',
          gap: 20,
        }}>
          {/* Card 01 — tall left, span 2 rows */}
          <FeatureCard
            card={cards[0]}
            style={isMobileLocal ? { minHeight: 360 } : { gridColumn: '1 / 2', gridRow: '1 / 3', minHeight: '28rem' }}
          />
          {/* Card 02 — wide top right, col span 2 */}
          <FeatureCard
            card={cards[1]}
            style={isMobileLocal ? { minHeight: 280 } : { gridColumn: '2 / 4', gridRow: '1 / 2', minHeight: 220 }}
          />
          {/* Card 03 — wide bottom right, col span 2 */}
          <FeatureCard
            card={cards[2]}
            style={isMobileLocal ? { minHeight: 320 } : { gridColumn: '2 / 4', gridRow: '2 / 3', minHeight: 220 }}
          />
        </div>
      </div>
    </section>
  )
}

// Versión vieja (scroll-stacking) — preservada por si querés volver a ese
// estilo. No se usa en HomeView pero queda como referencia.
function _HowItWorksSectionLegacy() {
  const steps = [
    {
      num:'01',
      Icon:QrCode,
      eyebrow:'PASO UNO',
      title:'Escaneá',
      desc:'Mostrá el QR del local y unite al club en segundos. Sin descargar nada, sin papelitos.',
      pills:['QR único por local', 'Sin app extra', 'Funciona offline'],
      accent:'#7131E1',         // violeta — sistema "stars"
      accentDark:'#7131E1',
      grad:'linear-gradient(135deg, #2A1140 0%, #1A0626 60%, #0d0218 100%)',
      visual:'qr',
    },
    {
      num:'02',
      Icon:Star,
      eyebrow:'PASO DOS',
      title:'Sumás',
      desc:'Cada visita suma estrellas o puntos automáticos. El comerciante escanea tu tarjeta y listo.',
      pills:['Estrellas o puntos', 'Suma automática', 'Sin trámite'],
      accent:'#EC4899',         // fucsia — sistema "points"
      accentDark:'#DB2777',
      grad:'linear-gradient(135deg, #2A0E22 0%, #1B0612 60%, #0F0309 100%)',
      visual:'sparks',
    },
    {
      num:'03',
      Icon:Gift,
      eyebrow:'PASO TRES',
      title:'Canjeás',
      desc:'Usás lo acumulado para llevarte premios reales: cafés, descuentos, productos y más.',
      pills:['Premios reales', 'Descuentos exclusivos', 'Stock en vivo'],
      accent:'#FE5000',         // naranja — color CTA marca
      accentDark:'#EA580C',
      grad:'linear-gradient(135deg, #2B1308 0%, #1A0A04 60%, #0F0502 100%)',
      visual:'gift',
    },
  ]

  const containerRef = useRef(null)
  const cardRefs     = useRef([])

  const [isMobile,      setIsMobile]      = useState(false)
  const [reducedMotion, setReducedMotion] = useState(false)
  const [activeCard,    setActiveCard]    = useState(0)
  const [showDots,      setShowDots]      = useState(false)
  const [transforms,    setTransforms]    = useState([
    { scale:1, opacity:1 }, { scale:1, opacity:1 }, { scale:1, opacity:1 },
  ])

  useEffect(() => {
    const mq = window.matchMedia('(prefers-reduced-motion: reduce)')
    setReducedMotion(mq.matches)
    const h = e => setReducedMotion(e.matches)
    mq.addEventListener('change', h)
    return () => mq.removeEventListener('change', h)
  }, [])

  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth < 768)
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  useEffect(() => {
    if (reducedMotion) { setShowDots(false); return }
    const topBase = isMobile ? 80  : 100
    const topStep = isMobile ? 25  : 30

    function handleScroll() {
      if (!containerRef.current) return
      const rect  = containerRef.current.getBoundingClientRect()
      const inView = rect.top < window.innerHeight - 60 && rect.bottom > 60
      setShowDots(inView)
      if (!inView) return

      let active = 0
      steps.forEach((_, i) => {
        const el = cardRefs.current[i]
        if (!el) return
        if (el.getBoundingClientRect().top <= topBase + i * topStep + 4) active = i
      })

      setActiveCard(active)
      setTransforms(steps.map((_, i) => ({
        scale:   i < active ? 0.97 : 1,
        opacity: i < active ? 0.85 : 1,
      })))
    }

    window.addEventListener('scroll', handleScroll, { passive: true })
    handleScroll()
    return () => window.removeEventListener('scroll', handleScroll)
  }, [reducedMotion, isMobile])

  const topBase = isMobile ? 80  : 100
  const topStep = isMobile ? 25  : 30
  // Altura de cada card. Achicada en desktop para que el contenido más
  // chico (título 56, padding 36) no deje aire muerto. En mobile sigue
  // siendo más alto porque texto + visual van stackeados.
  const cardH   = isMobile ? 520 : 380
  const cardMT  = isMobile ? 180 : 200

  // Cada card es un container con grad oscuro tintado del color de marca
  // de ese step + chrome de "liquid glass" (highlight superior + borde
  // gradient via ::before). Sin padding fijo: el contenido interno
  // maneja su propia geometría asimétrica.
  // El className "liquid-glass" agrega el highlight superior y el frame
  // gradient sutil que respira con el resto del lenguaje del home.
  const cardBase = (s, i, extra = {}) => ({
    borderRadius:        24,
    boxSizing:           'border-box',
    background:          `${s.grad}, rgba(255,255,255,0.01)`,
    backgroundBlendMode: 'normal, luminosity',
    boxShadow:           `0 30px 60px -20px ${s.accentDark}66, inset 0 1px 1px rgba(255,255,255,0.10)`,
    position:            'relative',
    overflow:            'hidden',
    ...extra,
  })

  // Visual decorativo único por step. Cada uno renderiza un patrón distinto
  // que evoca la acción (QR, sparks/estrellas, gift+sparkles).
  const StepVisual = ({ kind, accent }) => {
    if (kind === 'qr') {
      // Grid 7x7 estilo QR: marcadores en las 3 esquinas + dots aleatorios
      // en el centro. Solo CSS/divs, sin assets.
      const filled = new Set([
        // esquina top-left (3x3)
        0,1,2,7,9,14,15,16,
        // esquina top-right (3x3)
        4,5,6,11,13,18,19,20,
        // esquina bottom-left (3x3)
        28,29,30,35,37,42,43,44,
        // dots dispersos en el medio
        24,25,26,31,33,38,39,
      ])
      return (
        <div style={{ display:'grid', gridTemplateColumns:'repeat(7, 1fr)', gap:5, width:'100%', maxWidth: isMobile ? 180 : 220, aspectRatio:'1/1' }}>
          {Array.from({ length: 49 }).map((_, idx) => (
            <div key={idx} style={{
              borderRadius: 4,
              background: filled.has(idx) ? accent : 'rgba(255,255,255,0.05)',
              boxShadow: filled.has(idx) ? `0 0 8px ${accent}80` : 'none',
              transition: 'all 280ms ease',
            }} />
          ))}
        </div>
      )
    }
    if (kind === 'sparks') {
      // Estrellas flotantes. Tamaño base bajado: en desktop ahora ~1.1×
      // (era 1.4×) para que no domine sobre el texto del lado izquierdo.
      const scale = isMobile ? 0.9 : 1.1
      const sparks = [
        { left:'12%', top:'20%', size:38, delay:0    },
        { left:'68%', top:'10%', size:26, delay:600  },
        { left:'82%', top:'46%', size:42, delay:300  },
        { left:'24%', top:'62%', size:30, delay:900  },
        { left:'52%', top:'76%', size:22, delay:1200 },
        { left:'46%', top:'34%', size:18, delay:450  },
      ]
      return (
        <div style={{ position:'relative', width:'100%', height:'100%', minHeight: isMobile ? 180 : 220 }}>
          {sparks.map((sp, idx) => (
            <div key={idx} style={{
              position:'absolute', left:sp.left, top:sp.top,
            }}>
              <Star size={Math.round(sp.size * scale)} color={accent} fill={accent} strokeWidth={0} style={{ filter:`drop-shadow(0 0 12px ${accent}88)` }} />
            </div>
          ))}
        </div>
      )
    }
    if (kind === 'gift') {
      // Caja de regalo grande en el centro con sparkles que irradian.
      const sparkles = [
        { x:'18%', y:'22%' }, { x:'78%', y:'18%' }, { x:'12%', y:'72%' },
        { x:'82%', y:'78%' }, { x:'52%', y:'10%' }, { x:'92%', y:'48%' },
        { x:'8%',  y:'46%' }, { x:'48%', y:'90%' },
      ]
      const giftSz = isMobile ? 100 : 120
      const giftIconSz = isMobile ? 48 : 58
      const sparkleSz = isMobile ? 18 : 20
      return (
        <div style={{ position:'relative', width:'100%', height:'100%', minHeight: isMobile ? 180 : 200, display:'flex', alignItems:'center', justifyContent:'center' }}>
          {/* Halo radial detrás del regalo */}
          <div style={{
            position:'absolute', width:'70%', aspectRatio:'1/1',
            background:`radial-gradient(circle, ${accent}55 0%, transparent 70%)`,
            filter:'blur(24px)',
          }} />
          {/* Sparkles alrededor */}
          {sparkles.map((sp, idx) => (
            <div key={idx} style={{
              position:'absolute', left:sp.x, top:sp.y,
            }}>
              <Sparkles size={sparkleSz} color={accent} strokeWidth={1.8} style={{ filter:`drop-shadow(0 0 10px ${accent}99)` }} />
            </div>
          ))}
          {/* Gift icon central, grande */}
          <div style={{
            position:'relative', zIndex:1,
            width:giftSz, height:giftSz, borderRadius:28,
            background:`linear-gradient(135deg, ${accent}, ${accent}AA)`,
            display:'flex', alignItems:'center', justifyContent:'center',
            boxShadow:`0 16px 40px ${accent}80, inset 0 2px 0 rgba(255,255,255,0.30)`,
          }}>
            <Gift size={giftIconSz} color="#fff" strokeWidth={1.6} />
          </div>
        </div>
      )
    }
    return null
  }

  const CardInner = ({ s }) => (
    <div style={{
      position:'relative',
      width:'100%', height:'100%',
      padding: isMobile ? '28px 24px' : '36px 44px',
      display:'grid',
      gridTemplateColumns: isMobile ? '1fr' : '1.2fr 1fr',
      gap: isMobile ? 24 : 36,
      alignItems:'center',
    }}>
      {/* Número GIGANTE de fondo, ahora en Instrument Serif italic en
          vez de sans-bold outline — le da elegancia tipo landing
          cinematográfica. Pintado en color del step a baja opacidad. */}
      <div className="font-display" style={{
        position:'absolute',
        top: isMobile ? -28 : -34,
        right: isMobile ? -6 : -4,
        fontSize: isMobile ? 220 : 200,
        color: `${s.accent}26`,
        lineHeight:1,
        userSelect:'none', pointerEvents:'none',
        letterSpacing:'-.02em',
      }}>{s.num}</div>

      {/* Glow ambiente del color de marca atrás del visual */}
      <div style={{
        position:'absolute',
        right: isMobile ? '50%' : '15%',
        top:'50%',
        transform: isMobile ? 'translate(50%, -50%)' : 'translate(0, -50%)',
        width: isMobile ? 280 : 380,
        height: isMobile ? 280 : 380,
        background: `radial-gradient(circle, ${s.accent}33 0%, transparent 65%)`,
        filter:'blur(40px)',
        pointerEvents:'none',
      }} />

      {/* COLUMNA IZQUIERDA — texto */}
      <div style={{ position:'relative', zIndex:2, order: isMobile ? 2 : 1 }}>
        {/* Eyebrow chip con el color de marca */}
        <div style={{
          display:'inline-flex', alignItems:'center', gap:8,
          padding:'5px 12px', borderRadius:99,
          background:`${s.accent}1A`,
          border:`1px solid ${s.accent}55`,
          fontSize:10.5, fontFamily:FN, fontWeight:800,
          color:s.accent,
          letterSpacing:'.16em', textTransform:'uppercase',
          marginBottom:18,
        }}>
          <s.Icon size={12} strokeWidth={2.4} />
          {s.eyebrow}
        </div>

        {/* Título grande con underline accent. Bajamos a 56px en desktop
            (era 72) para que se sienta más balanceado en cards de 380px
            de alto. */}
        <div style={{ position:'relative', display:'inline-block', marginBottom:14 }}>
          <h3 style={{
            fontFamily:FN, fontSize: isMobile ? 40 : 56,
            fontWeight:900, color:'#fff', margin:0,
            lineHeight:1, letterSpacing:'-.025em',
            textShadow:`0 6px 24px ${s.accent}50`,
          }}>
            {s.title}
          </h3>
          <div style={{
            position:'absolute', left:0, bottom:-6,
            height: 4, width:'60%',
            background: `linear-gradient(90deg, ${s.accent}, ${s.accent}00)`,
            borderRadius: 99,
            boxShadow:`0 0 14px ${s.accent}, 0 0 4px ${s.accent}`,
          }} />
        </div>

        {/* Descripción — más chica en desktop para que el bloque de texto
            se vea proporcionado al título de 56px (no 72). */}
        <p style={{
          fontSize: isMobile ? 14.5 : 15,
          color:'rgba(255,255,255,0.78)',
          lineHeight:1.6, margin: isMobile ? '16px 0 20px' : '18px 0 20px',
          maxWidth:400,
        }}>
          {s.desc}
        </p>

        {/* Feature pills — patrón "small liquid-glass tag" inspirado en
            el space-travel landing: pill chiquito, glass casi
            transparente, texto blanco al 90%, sin checks adentro
            (más limpio). El borde lo da el ::before del liquid-glass. */}
        <div style={{ display:'flex', flexWrap:'wrap', gap:6 }}>
          {s.pills.map((p, idx) => (
            <div key={idx} className="liquid-glass" style={{
              padding:'5px 12px', borderRadius:99,
              fontSize:11, fontFamily:FN, fontWeight:500,
              color:'rgba(255,255,255,0.90)',
              letterSpacing:'.01em',
              whiteSpace:'nowrap',
            }}>
              {p}
            </div>
          ))}
        </div>
      </div>

      {/* COLUMNA DERECHA — visual decorativo único del step */}
      <div style={{
        position:'relative', zIndex:2,
        order: isMobile ? 1 : 2,
        display:'flex', alignItems:'center', justifyContent:'center',
        minHeight: isMobile ? 200 : 280,
      }}>
        <StepVisual kind={s.visual} accent={s.accent} />
      </div>
    </div>
  )

  const sectionHeader = (
    <>
      <div style={{ textAlign:'center', marginBottom:14 }}>
        <span className="liquid-glass" style={{ display:'inline-block', borderRadius:99, padding:'6px 20px', fontSize:11, color:'rgba(255,255,255,0.55)', fontFamily:FN, fontWeight:700, letterSpacing:'.10em', textTransform:'uppercase' }}>Así de fácil</span>
      </div>
      <h2 style={{ fontFamily:FN, fontSize:'clamp(22px,3.5vw,38px)', fontWeight:900, color:C.white, textAlign:'center', marginBottom: isMobile ? 40 : 52, lineHeight:1.1 }}>
        Cómo <span className="font-display" style={{ fontWeight:400, letterSpacing:'-.01em' }}>funciona.</span>
      </h2>
    </>
  )

  /* ── Reduced motion: plain vertical stack ── */
  if (reducedMotion) return (
    <section style={{ padding:'100px 20px' }}>
      <style>{`
        @keyframes step-spark-pulse {
          0%, 100% { transform: scale(1); opacity: 0.85; }
          50%      { transform: scale(1.18); opacity: 1; }
        }
      `}</style>
      {sectionHeader}
      <div style={{ maxWidth:860, margin:'0 auto', display:'flex', flexDirection:'column', gap:20 }}>
        {steps.map((s, i) => (
          <div key={i} style={cardBase(s, i, { minHeight: isMobile ? 540 : 460 })}>
            <CardInner s={s} />
          </div>
        ))}
      </div>
    </section>
  )

  /* ── Scroll-stacking layout ── */
  return (
    <section style={{ padding:'100px 20px 0' }}>
      {/* Keyframes para los visuals decorativos de los cards (sparks pulse). */}
      <style>{`
        @keyframes step-spark-pulse {
          0%, 100% { transform: scale(1); opacity: 0.85; }
          50%      { transform: scale(1.18); opacity: 1; }
        }
      `}</style>
      {sectionHeader}

      <div ref={containerRef} style={{ position:'relative', paddingBottom: isMobile ? 120 : 160 }}>
        {steps.map((s, i) => (
          <div
            key={i}
            ref={el => cardRefs.current[i] = el}
            style={{ position:'sticky', top: topBase + i * topStep, zIndex: i + 1, marginTop: i > 0 ? cardMT : 0 }}
          >
            <div style={cardBase(s, i, {
              height:     cardH,
              maxWidth:   860,
              margin:     '0 auto',
              transform:  `scale(${transforms[i].scale})`,
              opacity:    transforms[i].opacity,
              transition: 'transform 0.35s cubic-bezier(0.23,1,0.32,1), opacity 0.35s ease',
              willChange: 'transform, opacity',
            })}>
              <CardInner s={s} />
            </div>
          </div>
        ))}
      </div>

      {/* Progress dots — fixed at viewport bottom while section is in view */}
      {showDots && (
        <div style={{ position:'fixed', bottom:24, left:0, right:0, display:'flex', justifyContent:'center', zIndex:300, pointerEvents:'none' }}>
          <div style={{ display:'flex', gap:8, alignItems:'center', padding:'7px 14px', background:'rgba(0,0,0,0.5)', backdropFilter:'blur(12px)', WebkitBackdropFilter:'blur(12px)', borderRadius:99, border:'1px solid rgba(255,255,255,0.12)' }}>
            {steps.map((_, i) => (
              <div key={i} style={{
                width:6, height:6, borderRadius:'50%', background:'#fff',
                opacity:   i <= activeCard ? 1 : 0.3,
                transform: i === activeCard ? 'scale(1.3)' : 'scale(1)',
                transition:'opacity 0.3s ease, transform 0.3s ease',
              }} />
            ))}
          </div>
        </div>
      )}
    </section>
  )
}

// HeroSlider removed — replaced by HeroSection
function _HeroSlider({ setView, profile }) {
  const [current, setCurrent]   = useState(0)
  const [autoPlay, setAutoPlay] = useState(true)
  const [isDesktop, setIsDesktop] = useState(false)
  const resumeRef   = useRef(null)
  const touchStartX = useRef(null)

  const isOwner = profile?.role === 'commerce_owner'

  const slides = [
    {
      id: 1,
      title: 'Tus beneficios.',
      accent: 'Un solo QR.',
      sub:   'Sumá puntos en tus negocios favoritos y canjeá recompensas increíbles.',
      cta:   isOwner ? 'Ir a mi panel' : 'Ver mis clubes',
      onCta: () => setView(isOwner ? 'commerce-settings' : 'client'),
      Icon:  QrCode,
      blob1: 'rgba(189,75,248,0.28)', blob2: 'rgba(254,80,0,0.18)',
      bg:    'radial-gradient(ellipse at 28% 38%, #6935BD 0%, #1a0040 50%, #09000e 100%)',
    },
    {
      id: 2,
      title: 'Fidelizá a',
      accent: 'tus clientes.',
      sub:   'Sistema de puntos y estrellas que hace que vuelvan una y otra vez.',
      cta:   'Crear mi club',
      onCta: () => setView('register-commerce'),
      Icon:  Users,
      blob1: 'rgba(254,80,0,0.22)', blob2: 'rgba(189,75,248,0.18)',
      bg:    'radial-gradient(ellipse at 72% 30%, #7131E1 0%, #1a0040 50%, #09000e 100%)',
    },
    {
      id: 3,
      title: 'Premios que',
      accent: 'enamoran.',
      sub:   'Creá un catálogo irresistible y convertí visitas en clientes fieles.',
      cta:   'Ver ejemplo',
      onCta: () => { window.location.href = '/club/cafe-berlin' },
      Icon:  Gift,
      blob1: 'rgba(236,72,153,0.28)', blob2: 'rgba(189,75,248,0.18)',
      bg:    'radial-gradient(ellipse at 50% 60%, #7c1fa0 0%, #1a0040 50%, #09000e 100%)',
    },
    {
      id: 4,
      title: 'Marketing',
      accent: 'automático.',
      sub:   'Mensajes a clientes inactivos, cerca de premiar o recién llegados. Sin esfuerzo.',
      cta:   'Empezar gratis',
      onCta: () => setView('register-commerce'),
      Icon:  Bot,
      blob1: 'rgba(64,200,255,0.14)', blob2: 'rgba(189,75,248,0.22)',
      bg:    'radial-gradient(ellipse at 18% 70%, #6935BD 0%, #1a0040 50%, #09000e 100%)',
    },
    {
      id: 5,
      title: 'Empezá',
      accent: 'gratis.',
      sub:   'Sin tarjeta. Sin compromiso. Probá el plan gratuito y escalá cuando quieras.',
      cta:   'Crear cuenta',
      onCta: () => setView(isOwner ? 'commerce-settings' : 'client'),
      Icon:  Rocket,
      blob1: 'rgba(189,75,248,0.32)', blob2: 'rgba(254,80,0,0.22)',
      bg:    'radial-gradient(ellipse at 62% 28%, #7131E1 0%, #1a0040 50%, #09000e 100%)',
    },
  ]

  useEffect(() => {
    const check = () => setIsDesktop(window.innerWidth >= 768)
    check()
    window.addEventListener('resize', check)
    return () => window.removeEventListener('resize', check)
  }, [])

  useEffect(() => {
    if (!autoPlay) return
    const id = setInterval(() => setCurrent(p => (p + 1) % slides.length), 5000)
    return () => clearInterval(id)
  }, [autoPlay, slides.length])

  useEffect(() => () => { if (resumeRef.current) clearTimeout(resumeRef.current) }, [])

  function goTo(index) {
    setCurrent(index)
    setAutoPlay(false)
    if (resumeRef.current) clearTimeout(resumeRef.current)
    resumeRef.current = setTimeout(() => setAutoPlay(true), 10000)
  }
  const next = () => goTo((current + 1) % slides.length)
  const prev = () => goTo((current - 1 + slides.length) % slides.length)

  function onTouchStart(e) { touchStartX.current = e.touches[0].clientX }
  function onTouchEnd(e) {
    if (touchStartX.current === null) return
    const dx = e.changedTouches[0].clientX - touchStartX.current
    if (Math.abs(dx) > 50) dx < 0 ? next() : prev()
    touchStartX.current = null
  }

  return (
    <div
      style={{ position:'relative', width:'100%', height:'85vh', minHeight:600, overflow:'hidden', background:'#09000e' }}
      onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}
    >
      {slides.map((s, i) => (
        <div key={s.id} style={{
          position:'absolute', inset:0,
          opacity: i === current ? 1 : 0,
          transform: i === current ? 'scale(1)' : 'scale(1.03)',
          transition: 'opacity 700ms cubic-bezier(0.23,1,0.32,1), transform 700ms cubic-bezier(0.23,1,0.32,1)',
          pointerEvents: i === current ? 'auto' : 'none',
        }}>
          {/* Background */}
          <div style={{ position:'absolute', inset:0, background:s.bg }} />
          <div style={{ position:'absolute', top:'-20%', left:'-10%', width:'65vw', height:'65vw', borderRadius:'50%', background:`radial-gradient(circle, ${s.blob1} 0%, transparent 70%)`, filter:'blur(70px)', pointerEvents:'none' }} />
          <div style={{ position:'absolute', bottom:'-20%', right:'-10%', width:'55vw', height:'55vw', borderRadius:'50%', background:`radial-gradient(circle, ${s.blob2} 0%, transparent 70%)`, filter:'blur(90px)', pointerEvents:'none' }} />

          {/* Content — absolute fill so flex centering works against the full slide height */}
          <div style={{ position:'absolute', inset:0, zIndex:1, display:'flex', alignItems:'center', justifyContent:'center' }}>
            <div style={{
              width:'100%', maxWidth:1100,
              padding: isDesktop ? '0 64px' : '0 28px',
              display:'flex',
              flexDirection: isDesktop ? 'row' : 'column',
              alignItems:'center',
              justifyContent:'center',
              gap: isDesktop ? 64 : 36,
              textAlign: isDesktop ? 'left' : 'center',
            }}>
              {/* Text */}
              <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems: isDesktop ? 'flex-start' : 'center', gap:20 }}>
                <h1 style={{ fontFamily:FN, fontWeight:900, fontSize:'clamp(42px,7.5vw,78px)', lineHeight:0.93, letterSpacing:'-.03em', margin:0 }}>
                  <span style={{ color:'#fff', display:'block' }}>
                    <BlurText text={s.title} active={i === current} delay={0} />
                  </span>
                  <span style={{ display:'block', background:G, WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', backgroundClip:'text' }}>
                    <BlurText text={s.accent} active={i === current} delay={160} />
                  </span>
                </h1>
                <p style={{ fontSize:'clamp(15px,1.8vw,18px)', color:C.mist, maxWidth:460, lineHeight:1.75, margin:0 }}>
                  <BlurText text={s.sub} active={i === current} delay={360} />
                </p>
                <div style={{ opacity: i===current ? 1 : 0, transform: i===current ? 'translateY(0)' : 'translateY(10px)', transition:'opacity 550ms ease-out 480ms, transform 550ms cubic-bezier(0.23,1,0.32,1) 480ms' }}>
                  <GBtn onClick={s.onCta} style={{ fontSize:15, padding:'14px 32px', marginTop:4 }}>
                    {s.cta} →
                  </GBtn>
                </div>
              </div>

              {/* Visual placeholder */}
              <div style={{
                flexShrink:0,
                width: isDesktop ? 260 : 140, height: isDesktop ? 340 : 140,
                borderRadius: isDesktop ? 36 : 32,
                background:'rgba(255,255,255,0.06)',
                backdropFilter:'blur(24px)', WebkitBackdropFilter:'blur(24px)',
                border:'1px solid rgba(255,255,255,0.12)',
                display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', gap:16,
                boxShadow:'0 32px 80px rgba(0,0,0,0.45)',
                position:'relative', overflow:'hidden',
              }}>
                <div style={{ position:'absolute', top:-20, left:-20, width:120, height:120, borderRadius:'50%', background:'rgba(189,75,248,0.18)', filter:'blur(30px)', pointerEvents:'none' }} />
                <s.Icon size={isDesktop ? 64 : 44} strokeWidth={1.1} color='rgba(255,255,255,0.80)' style={{ position:'relative', zIndex:1 }} />
                {isDesktop && (
                  <>
                    <div style={{ width:'70%', height:6, borderRadius:99, background:'rgba(255,255,255,0.10)', position:'relative', zIndex:1 }} />
                    <div style={{ width:'50%', height:6, borderRadius:99, background:'rgba(255,255,255,0.06)', position:'relative', zIndex:1 }} />
                  </>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}

      {/* Left arrow */}
      <button onClick={prev}
        onMouseEnter={e => e.currentTarget.style.background='rgba(255,255,255,0.16)'}
        onMouseLeave={e => e.currentTarget.style.background='rgba(255,255,255,0.08)'}
        style={{ position:'absolute', left:16, top:'50%', transform:'translateY(-50%)', zIndex:20, width:44, height:44, borderRadius:'50%', background:'rgba(255,255,255,0.08)', backdropFilter:'blur(16px)', WebkitBackdropFilter:'blur(16px)', border:'1px solid rgba(255,255,255,0.15)', display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', color:'#fff', transition:'background .2s' }}>
        <ChevronLeft size={22} strokeWidth={2} />
      </button>

      {/* Right arrow */}
      <button onClick={next}
        onMouseEnter={e => e.currentTarget.style.background='rgba(255,255,255,0.16)'}
        onMouseLeave={e => e.currentTarget.style.background='rgba(255,255,255,0.08)'}
        style={{ position:'absolute', right:16, top:'50%', transform:'translateY(-50%)', zIndex:20, width:44, height:44, borderRadius:'50%', background:'rgba(255,255,255,0.08)', backdropFilter:'blur(16px)', WebkitBackdropFilter:'blur(16px)', border:'1px solid rgba(255,255,255,0.15)', display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', color:'#fff', transition:'background .2s' }}>
        <ChevronRight size={22} strokeWidth={2} />
      </button>

      {/* Dot indicators */}
      <div style={{ position:'absolute', bottom:36, left:'50%', transform:'translateX(-50%)', zIndex:20, display:'flex', alignItems:'center', gap:8 }}>
        {slides.map((_, i) => (
          <button key={i} onClick={() => goTo(i)}
            onMouseEnter={e => { if (i !== current) e.currentTarget.style.background='rgba(255,255,255,0.60)' }}
            onMouseLeave={e => { if (i !== current) e.currentTarget.style.background='rgba(255,255,255,0.35)' }}
            style={{ width: i === current ? 28 : 8, height:8, borderRadius:99, background: i === current ? '#fff' : 'rgba(255,255,255,0.35)', border:'none', padding:0, cursor:'pointer', transition:'all 300ms cubic-bezier(0.23,1,0.32,1)' }}
          />
        ))}
      </div>

      {/* Autoplay progress bar */}
      {autoPlay && (
        <div style={{ position:'absolute', bottom:0, left:0, right:0, height:3, background:'rgba(255,255,255,0.08)', zIndex:20, overflow:'hidden' }}>
          <div key={current} style={{ height:'100%', background:G, transformOrigin:'left', animation:'slider-progress 5s linear forwards' }} />
        </div>
      )}

      {/* Bottom section fade */}
      <div style={{ position:'absolute', bottom:0, left:0, right:0, height:120, background:'linear-gradient(to bottom, transparent, #09000e)', pointerEvents:'none', zIndex:10 }} />
    </div>
  )
}

// ─── TESTIMONIALS ─────────────────────────────────────────────────────────────
// Sección de testimonios deshabilitada hasta tener reseñas reales —
// igual que ReviewsSection. Los 3 nombres ficticios (María González,
// Carlos Rodríguez, Laura Martínez) eran demos.
function TestimonialsSection() {
  if (!REVIEWS_ENABLED) return null
  const items = [
    { name:'María González', role:'Dueña de Café Aroma',     location:'Buenos Aires', text:'Aumentamos un 40% las visitas recurrentes en solo 2 meses. Mis clientes aman juntar estrellitas.' },
    { name:'Carlos Rodríguez', role:'Barbería Premium',       location:'Córdoba',      text:'La app es súper fácil de usar. Mis clientes vuelven más seguido para completar su tarjeta.' },
    { name:'Laura Martínez', role:'Heladería Dolce',          location:'Rosario',      text:'El mejor sistema de fidelización que probé. Simple, bonito y mis clientes lo entienden al toque.' },
  ]
  const [hov, setHov] = useState(-1)
  return (
    <section style={{ padding:'80px 20px', position:'relative', overflow:'hidden' }}>
      {/* bg blob */}
      <div style={{ position:'absolute', top:0, right:0, width:500, height:500, borderRadius:'50%', background:'radial-gradient(circle, rgba(236,72,153,0.10) 0%, transparent 70%)', filter:'blur(60px)', pointerEvents:'none' }} />

      <div style={{ maxWidth:1080, margin:'0 auto' }}>
        {/* Badge */}
        <div style={{ display:'flex', justifyContent:'center', marginBottom:20 }}>
          <span className="liquid-glass" style={{ borderRadius:99, padding:'6px 20px', fontSize:11, color:'rgba(255,255,255,0.55)', fontFamily:FN, fontWeight:700, letterSpacing:'.10em', textTransform:'uppercase' }}>Testimonios</span>
        </div>

        {/* Title */}
        <h2 style={{ fontFamily:FN, fontSize:'clamp(24px,4vw,42px)', fontWeight:900, color:C.white, textAlign:'center', marginBottom:14, lineHeight:1.1 }}>
          <BlurText text="Lo que dicen nuestros clientes" delay={100} />
        </h2>
        <p style={{ fontFamily:FI, fontSize:15, color:'rgba(255,255,255,0.50)', textAlign:'center', marginBottom:56, maxWidth:560, margin:'0 auto 56px' }}>
          Comercios de toda Argentina ya confían en Benefix para fidelizar a sus clientes.
        </p>

        {/* Grid */}
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit, minmax(280px, 1fr))', gap:20 }}>
          {items.map((t, i) => (
            <div key={i} className="liquid-glass"
              style={{ borderRadius:24, padding:'28px 28px 24px', display:'flex', flexDirection:'column', gap:0, transition:'transform 280ms cubic-bezier(0.23,1,0.32,1)', transform: hov===i ? 'scale(1.02)' : 'scale(1)' }}
              onMouseEnter={() => setHov(i)} onMouseLeave={() => setHov(-1)}>
              {/* Quote mark */}
              <div style={{ fontFamily:'Georgia, serif', fontSize:72, lineHeight:1, color:'rgba(168,85,247,0.25)', marginBottom:8, marginTop:-8 }}>"</div>
              {/* Text */}
              <p style={{ fontFamily:FI, fontSize:15, color:'rgba(255,255,255,0.80)', lineHeight:1.65, marginBottom:20, flex:1, fontStyle:'italic' }}>{t.text}</p>
              {/* Stars */}
              <div style={{ display:'flex', gap:3, marginBottom:20 }}>
                {[0,1,2,3,4].map(j => <Star key={j} size={16} color='#facc15' fill='#facc15' strokeWidth={0} />)}
              </div>
              {/* Author */}
              <div style={{ display:'flex', alignItems:'center', gap:14 }}>
                <div style={{ width:44, height:44, borderRadius:'50%', background:'#7131E1', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                  <span style={{ fontFamily:FN, fontSize:14, fontWeight:900, color:'#fff' }}>
                    {t.name.split(' ').map(n=>n[0]).join('')}
                  </span>
                </div>
                <div>
                  <div style={{ fontFamily:FN, fontSize:13, fontWeight:700, color:C.white }}>{t.name}</div>
                  <div style={{ fontSize:11, color:C.mist, marginTop:1 }}>{t.role}</div>
                  <div style={{ fontSize:10, color:C.dust, marginTop:1 }}>{t.location}</div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}

// ─── CTA FINAL ────────────────────────────────────────────────────────────────
function CtaSection({ setView }) {
  return (
    <section style={{
      padding:'100px 20px',
      position:'relative',
      background:'#000',
      overflow:'hidden',
      isolation:'isolate',  // contiene el video al wrapper, no se filtra al resto
    }}>
      {/* Video de fondo — mismo HLS de Mux que el hero V2.
          Full-bleed. SIN overlays de color (el dueño no quiere los gradients
          de marca acá). Mantenemos solo un velo oscuro plano sutil para que
          el texto siga siendo legible sobre el video. */}
      <div style={{
        position:'absolute', inset:0, zIndex:0,
        pointerEvents:'none',
      }}>
        <HLSVideoPlayer
          src="https://stream.mux.com/9JXDljEVWYwWu01PUkAemafDugK89o01BR6zqJ3aS9u00A.m3u8"
          autoPlay muted loop playsInline preload="auto"
          style={{
            position:'absolute', inset:0,
            width:'100%', height:'100%',
            objectFit:'cover',
            // Mismo mask radial elíptico que el hero para fundir bordes
            // contra el negro de la página (sin corte duro).
            WebkitMaskImage: 'radial-gradient(ellipse at center, #000 30%, rgba(0,0,0,0.85) 70%, rgba(0,0,0,0.4) 90%, transparent 100%)',
            maskImage:       'radial-gradient(ellipse at center, #000 30%, rgba(0,0,0,0.85) 70%, rgba(0,0,0,0.4) 90%, transparent 100%)',
          }}
        />
        {/* Velo oscuro neutro para legibilidad — sin tinte de color. */}
        <div style={{
          position:'absolute', inset:0,
          background:'rgba(0,0,0,0.45)',
        }} />
      </div>

      <div style={{ maxWidth:720, margin:'0 auto', textAlign:'center', position:'relative', zIndex:1 }}>
        <h2 style={{ fontFamily:FN, fontSize:'clamp(28px,5vw,52px)', fontWeight:900, color:C.white, marginBottom:20, lineHeight:1.1 }}>
          <BlurText text="¿Listo para fidelizar?" delay={100} />
        </h2>
        <p style={{ fontFamily:FI, fontSize:16, color:'rgba(255,255,255,0.65)', marginBottom:40, lineHeight:1.7, maxWidth:480, margin:'0 auto 40px' }}>
          Empezá gratis hoy. Sin tarjeta de crédito, sin compromiso.<br />
          En lo que dura un café tenés tu club andando.
        </p>
        <div style={{ display:'flex', flexWrap:'wrap', gap:12, justifyContent:'center', marginBottom:24 }}>
          <Btn style={{ fontSize:15, padding:'14px 32px' }} onClick={() => setView('register-commerce')}>
            Empezá gratis <ArrowRight size={18} strokeWidth={2.5} />
          </Btn>
          <Btn variant="outline" style={{ fontSize:15, padding:'14px 32px' }} onClick={() => window.open('/demo', '_blank')}>
            Ver demo
          </Btn>
        </div>
        <p style={{ fontFamily:FI, fontSize:12, color:'rgba(255,255,255,0.50)' }}>
          Sin contrato · Sin permanencia · Cancelá cuando quieras
        </p>
      </div>
    </section>
  )
}

